package dev.veld.jetbrains

import com.intellij.lang.annotation.AnnotationHolder
import com.intellij.lang.annotation.Annotator
import com.intellij.lang.annotation.HighlightSeverity
import com.intellij.openapi.editor.DefaultLanguageHighlighterColors
import com.intellij.openapi.editor.colors.TextAttributesKey
import com.intellij.openapi.util.TextRange
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiFile

/**
 * Real-time in-editor annotator for Veld files.
 *
 * Provides:
 *   • Semantic highlighting — distinct colors for every declaration kind, reference kind,
 *     field names, enum values, HTTP methods, path params, @annotations.
 *   • Validation — undefined types, bad imports, invalid HTTP methods, brace mismatches.
 *
 * The annotator operates on the PsiFile level (whole-file pass) so it can correctly
 * resolve cross-line state (brace depth, enum body, model body).
 */
class VeldAnnotator : Annotator {

    companion object {
        // ── Declaration colors ───────────────────────────────────────────────
        val MODEL_DECLARATION = TextAttributesKey.createTextAttributesKey(
            "VELD_MODEL_DECLARATION", DefaultLanguageHighlighterColors.CLASS_NAME
        )
        val ENUM_DECLARATION = TextAttributesKey.createTextAttributesKey(
            "VELD_ENUM_DECLARATION", DefaultLanguageHighlighterColors.INTERFACE_NAME
        )
        val MODULE_DECLARATION = TextAttributesKey.createTextAttributesKey(
            "VELD_MODULE_DECLARATION", DefaultLanguageHighlighterColors.CLASS_NAME
        )
        val ACTION_NAME = TextAttributesKey.createTextAttributesKey(
            "VELD_ACTION_NAME", DefaultLanguageHighlighterColors.FUNCTION_DECLARATION
        )

        // ── Reference colors ─────────────────────────────────────────────────
        val MODEL_REFERENCE = TextAttributesKey.createTextAttributesKey(
            "VELD_MODEL_REFERENCE", DefaultLanguageHighlighterColors.CLASS_REFERENCE
        )
        val ENUM_REFERENCE = TextAttributesKey.createTextAttributesKey(
            "VELD_ENUM_REFERENCE", DefaultLanguageHighlighterColors.INTERFACE_NAME
        )
        val MODULE_REFERENCE = TextAttributesKey.createTextAttributesKey(
            "VELD_MODULE_REFERENCE", DefaultLanguageHighlighterColors.CLASS_REFERENCE
        )

        // ── Member colors ────────────────────────────────────────────────────
        val FIELD_NAME = TextAttributesKey.createTextAttributesKey(
            "VELD_FIELD_NAME", DefaultLanguageHighlighterColors.INSTANCE_FIELD
        )
        val ENUM_VALUE = TextAttributesKey.createTextAttributesKey(
            "VELD_ENUM_VALUE", DefaultLanguageHighlighterColors.CONSTANT
        )

        // ── Annotation color ─────────────────────────────────────────────────
        val ANNOTATION = TextAttributesKey.createTextAttributesKey(
            "VELD_ANNOTATION", DefaultLanguageHighlighterColors.METADATA
        )

        // ── Path parameter color ─────────────────────────────────────────────
        val PATH_PARAM = TextAttributesKey.createTextAttributesKey(
            "VELD_PATH_PARAM", DefaultLanguageHighlighterColors.PARAMETER
        )

        // ── Valid directive keys per block context ───────────────────────────
        /** Keys valid inside action { ... } */
        val ACTION_KEYS = setOf("method", "path", "input", "output", "query", "stream",
            "middleware", "errors", "description")
        /** Keys valid inside module { ... } (top-level, outside actions) */
        val MODULE_KEYS = setOf("description", "prefix")
    }

    // Simple context tracker so we highlight enum values vs. model fields correctly.
    private enum class BlockKind { NONE, MODEL, ENUM, CONSTANTS, MODULE, ACTION }

    override fun annotate(element: PsiElement, holder: AnnotationHolder) {
        if (element !is PsiFile) return
        if (element.virtualFile?.extension != "veld") return

        val project = element.project
        val virtualFile = element.virtualFile ?: return
        val service = VeldProjectService.getInstance(project)
        val content = element.text
        val lines = content.split("\n")

        // Keep the index fresh so visible-type lookups are accurate.
        service.reindexFile(virtualFile, content)

        val visibleModels = service.getVisibleModels(virtualFile).map { it.name }.toSet()
        val visibleEnums  = service.getVisibleEnums(virtualFile).map  { it.name }.toSet()
        val allTypes      = visibleModels + visibleEnums +
                            VeldLanguageSpec.BUILTIN_TYPES + VeldLanguageSpec.SPECIAL_TYPES

        // ── Line-by-line pass ────────────────────────────────────────────────
        var offset     = 0
        var braceDepth = 0
        var bracketDepth = 0  // tracks depth inside [...] lists (e.g. errors: [name:status])
        var blockStack = ArrayDeque<BlockKind>()  // tracks nested block kinds

        for (i in lines.indices) {
            val line        = lines[i]
            val trimmed     = line.trim()
            val lineStart   = offset
            val indentLen   = line.length - line.trimStart().length

            val openBraces   = trimmed.count { it == '{' }
            val closeBraces  = trimmed.count { it == '}' }
            val openBrackets = trimmed.count { it == '[' }
            val closeBrackets = trimmed.count { it == ']' }

            // Current block context (before brace adjustments this line)
            val currentBlock = blockStack.lastOrNull() ?: BlockKind.NONE

            // ── Semantic highlighting ────────────────────────────────────────

            when {
                // ── model declaration ────────────────────────────────────────
                trimmed.startsWith("model ") -> {
                    val m = Regex("""^model\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, MODEL_DECLARATION)
                        // extends parent
                        val ex = Regex("""extends\s+([A-Za-z_]\w*)""").find(trimmed)
                        if (ex != null) {
                            highlightWord(
                                ex.groupValues[1], line, lineStart, content.length, holder, MODEL_REFERENCE,
                                searchFrom = line.indexOf("extends")
                            )
                        }
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.MODEL)
                }

                // ── enum declaration ─────────────────────────────────────────
                trimmed.startsWith("enum ") -> {
                    val m = Regex("""^enum\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, ENUM_DECLARATION)
                    }
                    if (openBraces > closeBraces) {
                        blockStack.addLast(BlockKind.ENUM)
                        // Single-line enum: enum Role { admin user guest }
                        val inlineValues = Regex("""\{([^}]*)\}""").find(trimmed)?.groupValues?.get(1)
                        if (inlineValues != null) {
                            highlightEnumValues(inlineValues, line, lineStart, content.length,
                                line.indexOf('{'), holder)
                            blockStack.removeLast()  // immediately closed
                        }
                    }
                }

                // ── module declaration ────────────────────────────────────────
                trimmed.startsWith("module ") -> {
                    val m = Regex("""^module\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, MODULE_DECLARATION)
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.MODULE)
                }

                // ── constants declaration ─────────────────────────────────────
                trimmed.startsWith("constants ") || trimmed.startsWith("constant ") -> {
                    val m = Regex("""^constants?\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, ENUM_DECLARATION)
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.CONSTANTS)
                }

                // ── action declaration ────────────────────────────────────────
                trimmed.startsWith("action ") -> {
                    val m = Regex("""^action\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, ACTION_NAME)
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.ACTION)
                }

                // ── import / from-import ──────────────────────────────────
                trimmed.startsWith("import") || trimmed.startsWith("from") -> {
                    validateImport(trimmed, line, lineStart, content.length, virtualFile, service, holder)
                }

                // ── top-level prefix: /api/v1 ────────────────────────────────
                trimmed.startsWith("prefix:") && blockStack.isEmpty() -> {
                    // Valid top-level prefix directive — no special handling needed
                }

                // ── inside enum body: enum values ────────────────────────────
                currentBlock == BlockKind.ENUM && trimmed != "{" && trimmed != "}" &&
                        trimmed.isNotEmpty() && !trimmed.startsWith("//") -> {
                    highlightEnumValues(trimmed, line, lineStart, content.length, indentLen, holder)
                }

                // ── inside constants body: NAME: type = value ────────────────
                currentBlock == BlockKind.CONSTANTS && trimmed != "{" && trimmed != "}" &&
                        trimmed.isNotEmpty() && !trimmed.startsWith("//") -> {
                    // Highlight constant field name as FIELD_NAME
                    val constField = Regex("""^([A-Z_][A-Za-z0-9_]*)\s*:""").find(trimmed)
                    if (constField != null) {
                        highlightWord(constField.groupValues[1], line, lineStart, content.length, holder, FIELD_NAME)
                    }
                }

                // ── inside model/action body: directives and fields ───────────
                // Skip directive validation inside [...] lists (e.g. errors: [name:status, ...])
                currentBlock == BlockKind.MODEL || currentBlock == BlockKind.ACTION ||
                currentBlock == BlockKind.MODULE -> {
                    if (bracketDepth == 0) {
                        handleDirectiveOrField(
                            trimmed, line, lineStart, content.length,
                            visibleModels, visibleEnums, allTypes, holder, currentBlock
                        )
                    }
                }

                // ── closing braces ────────────────────────────────────────────
                trimmed == "}" -> { /* handled below */ }
            }

            // ── Brace and bracket depth tracking ────────────────────────────
            braceDepth += openBraces - closeBraces
            bracketDepth = maxOf(0, bracketDepth + openBrackets - closeBrackets)
            repeat(closeBraces) {
                if (blockStack.isNotEmpty()) blockStack.removeLast()
            }

            offset += line.length + 1  // +1 for \n
        }

        // ── Unclosed brace validation ────────────────────────────────────────
        if (braceDepth > 0) {
            val endOffset = content.length
            holder.newAnnotation(
                HighlightSeverity.ERROR,
                "Unclosed brace: $braceDepth opening brace(s) without matching closing brace(s)"
            ).range(TextRange((endOffset - (lines.lastOrNull()?.length ?: 0)).coerceAtLeast(0), endOffset))
                .create()
        } else if (braceDepth < 0) {
            holder.newAnnotation(
                HighlightSeverity.ERROR,
                "Extra closing brace(s): ${-braceDepth} closing brace(s) without matching opening brace(s)"
            ).range(TextRange(0, 1.coerceAtMost(content.length))).create()
        }
    }

    // ── Directive / field handling ───────────────────────────────────────────

    private fun handleDirectiveOrField(
        trimmed: String, line: String, lineStart: Int, contentLen: Int,
        models: Set<String>, enums: Set<String>, allTypes: Set<String>,
        holder: AnnotationHolder, blockKind: BlockKind
    ) {
        if (trimmed.startsWith("//") || trimmed == "{" || trimmed == "}" || trimmed.isEmpty()) return

        // ── Extract the key name if this is a key: value line ────────────────
        val keyMatch = Regex("""^([a-zA-Z_]\w*)\s*:""").find(trimmed)
        if (keyMatch != null && blockKind != BlockKind.MODEL) {
            val key = keyMatch.groupValues[1]
            // Validate directive keys based on block context
            if (blockKind == BlockKind.ACTION && key !in ACTION_KEYS) {
                val start = lineStart + line.indexOf(key)
                val end = start + key.length
                if (start >= lineStart && end <= contentLen && start < end) {
                    holder.newAnnotation(
                        HighlightSeverity.ERROR,
                        "Unknown action directive '$key'. Valid: ${ACTION_KEYS.sorted().joinToString(", ")}"
                    ).range(TextRange(start, end)).create()
                }
                return
            }
            if (blockKind == BlockKind.MODULE && key !in MODULE_KEYS) {
                val start = lineStart + line.indexOf(key)
                val end = start + key.length
                if (start >= lineStart && end <= contentLen && start < end) {
                    holder.newAnnotation(
                        HighlightSeverity.WARNING,
                        "Unexpected key '$key' inside module. Did you mean to put this inside an action?"
                    ).range(TextRange(start, end)).create()
                }
                return
            }
        }

        // ── method directive ──────────────────────────────────────────────────
        if (trimmed.startsWith("method:")) {
            val m = Regex("""method:\s*(\w+)""").find(trimmed)
            if (m != null) {
                val method = m.groupValues[1]
                if (!VeldLanguageSpec.isHttpMethod(method)) {
                    val start = lineStart + line.indexOf(method)
                    val end   = start + method.length
                    if (start >= 0 && end <= contentLen) {
                        holder.newAnnotation(
                            HighlightSeverity.ERROR,
                            "Invalid HTTP method '$method'. Valid: ${VeldLanguageSpec.HTTP_METHODS.joinToString(", ")}"
                        ).range(TextRange(start, end)).create()
                    }
                }
            }
            return
        }

        // ── path directive: highlight :param segments + show resolved path ──
        if (trimmed.startsWith("path:") || trimmed.startsWith("prefix:")) {
            val colonIdx = trimmed.indexOf(':')
            val pathVal  = trimmed.substring(colonIdx + 1).trim()
            highlightPathParams(pathVal, line, lineStart, contentLen, holder)

            // Show the full resolved path as a tooltip
            // We need to find the module prefix and app prefix from context
            val pathStart = lineStart + line.indexOf(pathVal)
            val pathEnd = pathStart + pathVal.length
            if (pathVal.isNotEmpty() && pathStart >= lineStart && pathEnd <= contentLen && pathStart < pathEnd) {
                holder.newAnnotation(HighlightSeverity.INFORMATION,
                    "Resolved: $pathVal (hover an action name to see the full route with all prefixes)")
                    .range(TextRange(pathStart, pathEnd))
                    .tooltip("Route path: <b>$pathVal</b><br/>This path will be combined with the app prefix and module prefix at generation time.")
                    .create()
            }
            return
        }

        // ── input / output / query directives — validate as type references ──
        if (trimmed.startsWith("input:") || trimmed.startsWith("output:") ||
            trimmed.startsWith("query:")
        ) {
            val colonIdx = trimmed.indexOf(':')
            if (colonIdx >= 0) {
                val typeExpr = trimmed.substring(colonIdx + 1).trim()
                highlightTypeReferences(typeExpr, line, lineStart, contentLen, models, enums, holder)
                validateTypeExpression(typeExpr, line, lineStart, contentLen, allTypes, holder)
            }
            return
        }

        // ── middleware directive — just a label name, not a type reference ───
        if (trimmed.startsWith("middleware:")) return

        // ── stream directive — type reference ────────────────────────────────
        if (trimmed.startsWith("stream:")) {
            val colonIdx = trimmed.indexOf(':')
            if (colonIdx >= 0) {
                val typeExpr = trimmed.substring(colonIdx + 1).trim()
                highlightTypeReferences(typeExpr, line, lineStart, contentLen, models, enums, holder)
                validateTypeExpression(typeExpr, line, lineStart, contentLen, allTypes, holder)
            }
            return
        }

        // ── errors directive — list of error names, not type references ──────
        if (trimmed.startsWith("errors:")) return

        // ── description directive: must be a quoted string ────────────────
        if (trimmed.startsWith("description:")) {
            val descColonIdx = trimmed.indexOf(':')
            val descVal = trimmed.substring(descColonIdx + 1).trim()
            if (descVal.isNotEmpty() && !descVal.startsWith("\"")) {
                val start = lineStart + line.indexOf(descVal, descColonIdx)
                val end = start + descVal.length
                if (start >= lineStart && end <= contentLen && start < end) {
                    holder.newAnnotation(
                        HighlightSeverity.ERROR,
                        "Description must be a quoted string, e.g. description: \"User management\""
                    ).range(TextRange(start, end)).create()
                }
            }
            return
        }

        // ── field definition inside a model ──────────────────────────────────
        val fieldMatch = Regex("""^([a-z_]\w*)(\??):\s*(.+?)(?:\s*//.*)?$""").find(trimmed)
        if (fieldMatch != null) {
            val fieldName    = fieldMatch.groupValues[1]
            val rawTypeExpr  = fieldMatch.groupValues[3].trim()

            // Highlight field name
            highlightWord(fieldName, line, lineStart, contentLen, holder, FIELD_NAME)

            // Strip @annotations (e.g. @default(user)) and = value before type processing
            val typeExpr = rawTypeExpr
                .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
                .replace(Regex("""@\w+(?:\([^)]*\))?"""), "")
                .replace(Regex("""@\w+\s+"[^"]*""""), "")
                .trim()

            // Highlight type references
            highlightTypeReferences(typeExpr, line, lineStart, contentLen, models, enums, holder)

            // Validate types
            validateTypeExpression(typeExpr, line, lineStart, contentLen, allTypes, holder)

            // Highlight @annotation(...) clauses on this field line
            highlightAnnotations(rawTypeExpr, line, lineStart, contentLen, holder)

            // Highlight = value default syntax
            highlightDefaultEquals(rawTypeExpr, line, lineStart, contentLen, holder)
        }
    }

    // ── Enum value highlighting ──────────────────────────────────────────────

    private fun highlightEnumValues(
        body: String, fullLine: String, lineStart: Int, contentLen: Int,
        searchFromCol: Int, holder: AnnotationHolder
    ) {
        for (m in Regex("""\b([a-zA-Z_]\w*)\b""").findAll(body)) {
            val start = lineStart + fullLine.indexOf(m.value, searchFromCol)
            val end   = start + m.value.length
            if (start >= lineStart && end <= contentLen && start < end) {
                highlightRange(holder, TextRange(start, end), ENUM_VALUE)
            }
        }
    }

    // ── = value default highlighting and validation ────────────────────────

    private fun highlightDefaultEquals(
        typeExprRaw: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder
    ) {
        val eqMatch = Regex("""=\s*("[^"]*"|-?\d+\.?\d*|true|false|[A-Za-z_]\w*)""").find(typeExprRaw) ?: return
        val colonIdx = line.indexOf(':')
        val searchFrom = if (colonIdx >= 0) colonIdx else 0

        // Highlight the = operator
        val eqIdx = line.indexOf('=', searchFrom)
        if (eqIdx >= 0) {
            val eqStart = lineStart + eqIdx
            val eqEnd = eqStart + 1
            if (eqStart >= lineStart && eqEnd <= contentLen && eqStart < eqEnd) {
                highlightRange(holder, TextRange(eqStart, eqEnd),
                    TextAttributesKey.createTextAttributesKey("VELD_OPERATOR",
                        DefaultLanguageHighlighterColors.OPERATION_SIGN))
            }
        }

        // Highlight the value
        val valStr = eqMatch.groupValues[1]
        val valStart = lineStart + line.indexOf(valStr, if (eqIdx >= 0) eqIdx else searchFrom)
        val valEnd = valStart + valStr.length
        if (valStart >= lineStart && valEnd <= contentLen && valStart < valEnd) {
            val valKey = when {
                valStr.startsWith("\"") -> TextAttributesKey.createTextAttributesKey("VELD_STRING_DEFAULT",
                    DefaultLanguageHighlighterColors.STRING)
                valStr == "true" || valStr == "false" -> TextAttributesKey.createTextAttributesKey("VELD_BOOL_DEFAULT",
                    DefaultLanguageHighlighterColors.KEYWORD)
                valStr.matches(Regex("""-?\d+\.?\d*""")) -> TextAttributesKey.createTextAttributesKey("VELD_NUMBER_DEFAULT",
                    DefaultLanguageHighlighterColors.NUMBER)
                else -> TextAttributesKey.createTextAttributesKey("VELD_IDENT_DEFAULT",
                    DefaultLanguageHighlighterColors.CONSTANT)
            }
            highlightRange(holder, TextRange(valStart, valEnd), valKey)
        }

        // Validate = value against field type (reuse validateDefaultValue)
        val fieldType = typeExprRaw
            .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
            .replace(Regex("""@\w+(?:\([^)]*\))?"""), "")
            .replace(Regex("""@\w+\s+"[^"]*""""), "")
            .replace("[]", "").replace("?", "").trim()
        val defaultVal = valStr
        val error = validateDefaultValue(fieldType, defaultVal)
        if (error != null) {
            if (valStart >= lineStart && valEnd <= contentLen && valStart < valEnd) {
                holder.newAnnotation(HighlightSeverity.ERROR, error.replace("@default for", "Default value for"))
                    .range(TextRange(valStart, valEnd)).create()
            }
        }
    }

    // ── @annotation(...) highlighting and validation ─────────────────────────

    private fun highlightAnnotations(
        typeExprRaw: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder
    ) {
        if (!typeExprRaw.contains('@')) return
        val colonIdx = line.indexOf(':')
        for (m in Regex("""@\w+(?:\([^)]*\))?""").findAll(typeExprRaw)) {
            val searchFrom = if (colonIdx >= 0) colonIdx else 0
            val start = lineStart + line.indexOf(m.value, searchFrom)
            val end   = start + m.value.length
            if (start >= lineStart && end <= contentLen && start < end) {
                highlightRange(holder, TextRange(start, end), ANNOTATION)
                // Validate annotation name
                val annName = m.value.substringAfter('@').substringBefore('(')
                if (annName !in VeldLanguageSpec.KNOWN_ANNOTATIONS) {
                    holder.newAnnotation(
                        HighlightSeverity.WARNING,
                        "Unknown annotation '@$annName'. Known: ${VeldLanguageSpec.KNOWN_ANNOTATIONS.joinToString(", ") { "@$it" }}"
                    ).range(TextRange(start, end)).create()
                }
                // Validate @default value matches field type
                if (annName == "default" && m.value.contains("(")) {
                    val defaultVal = m.value.substringAfter("(").substringBefore(")")
                    // Extract field type from the raw expression (before annotations and = value)
                    val fieldType = typeExprRaw
                        .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
                        .replace(Regex("""@\w+(?:\([^)]*\))?"""), "")
                        .replace("[]", "").replace("?", "").trim()
                    val error = validateDefaultValue(fieldType, defaultVal)
                    if (error != null) {
                        holder.newAnnotation(HighlightSeverity.ERROR, error)
                            .range(TextRange(start, end)).create()
                    }
                }
            }
        }
    }

    /** Validate that a @default value matches the field type. Returns error message or null. */
    private fun validateDefaultValue(fieldType: String, defaultVal: String): String? {
        val isQuoted = defaultVal.startsWith("\"")
        val isBool = defaultVal == "true" || defaultVal == "false"

        return when (fieldType) {
            "string", "date", "datetime", "uuid", "decimal" -> {
                if (!isQuoted) "@default for $fieldType must be a quoted string, got $defaultVal"
                else null
            }
            "int" -> when {
                isQuoted -> "@default for int must be a number, got $defaultVal"
                isBool -> "@default for int must be a number, got $defaultVal"
                defaultVal.contains(".") -> "@default for int must be a whole number, got $defaultVal"
                else -> null
            }
            "float" -> when {
                isQuoted -> "@default for float must be a number, got $defaultVal"
                isBool -> "@default for float must be a number, got $defaultVal"
                else -> null
            }
            "bool" -> {
                if (!isBool) "@default for bool must be true or false, got $defaultVal"
                else null
            }
            else -> null // enum or custom type — can't validate without more context
        }
    }

    // ── Path :param highlighting ─────────────────────────────────────────────

    private fun highlightPathParams(
        pathVal: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder
    ) {
        for (m in Regex(""":([\w]+)""").findAll(pathVal)) {
            val searchFrom = line.indexOf(':').let { if (it >= 0) it else 0 }
            val colonStart = lineStart + line.indexOf(":" + m.groupValues[1], searchFrom)
            val end        = colonStart + m.groupValues[1].length + 1
            if (colonStart >= lineStart && end <= contentLen && colonStart < end) {
                highlightRange(holder, TextRange(colonStart, end), PATH_PARAM)
            }
        }
    }

    // ── Type reference highlighting ──────────────────────────────────────────

    private fun highlightTypeReferences(
        typeExpr: String, line: String, lineStart: Int, contentLen: Int,
        models: Set<String>, enums: Set<String>, holder: AnnotationHolder
    ) {
        val colonIdx = line.indexOf(':')
        val searchFrom = if (colonIdx >= 0) colonIdx else 0

        for (m in Regex("""[A-Za-z_]\w*""").findAll(typeExpr)) {
            val typeName = m.value
            val start    = lineStart + line.indexOf(typeName, searchFrom)
            val end      = start + typeName.length
            if (start < lineStart || end > contentLen || start >= end) continue

            val key = when {
                models.contains(typeName) -> MODEL_REFERENCE
                enums.contains(typeName)  -> ENUM_REFERENCE
                VeldLanguageSpec.isSpecialType(typeName) ->
                    TextAttributesKey.createTextAttributesKey("VELD_GENERIC",
                        DefaultLanguageHighlighterColors.CLASS_NAME)
                else -> null
            }
            if (key != null) highlightRange(holder, TextRange(start, end), key)
        }
    }

    // ── Import validation ────────────────────────────────────────────────────

    private fun validateImport(
        trimmed: String, line: String, lineStart: Int, contentLen: Int,
        virtualFile: com.intellij.openapi.vfs.VirtualFile,
        service: VeldProjectService,
        holder: AnnotationHolder
    ) {
        // Accept all valid import formats:
        //   import @models/user    import @models/*    import @models
        //   import /models/user    import /models/*    import /models
        //   import models/user     import models/*     import models
        //   from @models import *  from /models import user  from models import *
        //   import "legacy/path.veld"
        val validPatterns = listOf(
            Regex("""import\s+@\w+(/[\w*]+)?"""),           // import @alias[/name|/*]
            Regex("""import\s+/\w+(/[\w*]+)?"""),           // import /path[/name|/*]
            Regex("""import\s+\w+(/[\w*]+)?"""),            // import alias[/name|/*]
            Regex("""import\s+"[^"]+""""),                   // import "legacy"
            Regex("""from\s+@?\w+\s+import\s+(\*|\w+)"""), // from @?alias import *|name
            Regex("""from\s+/\w+\s+import\s+(\*|\w+)""")   // from /path import *|name
        )
        if (validPatterns.any { it.matches(trimmed) }) {
            // Valid syntax — optionally validate resolved file exists
            val singleFile = Regex("""import\s+(@\w+/\w+)""").find(trimmed)
            if (singleFile != null) {
                val path = singleFile.groupValues[1]
                val resolved = service.resolveImport(path, virtualFile)
                if (resolved == null || !resolved.exists()) {
                    val atIdx = line.indexOf('@')
                    val start = lineStart + atIdx
                    val end   = lineStart + line.trimEnd().length
                    if (atIdx >= 0 && start < end && end <= contentLen) {
                        holder.newAnnotation(HighlightSeverity.WARNING,
                            "Cannot resolve import '$path'. File may not exist yet.")
                            .range(TextRange(start, end)).create()
                    }
                }
            }
        }
    }

    // ── Type validation ──────────────────────────────────────────────────────

    private fun validateTypeExpression(
        typeExpr: String, line: String, lineStart: Int, contentLen: Int,
        allTypes: Set<String>, holder: AnnotationHolder
    ) {
        // Strip @annotations and = value before validation
        val clean = typeExpr
            .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
            .replace(Regex("""@\w+\([^)]*\)"""), "")
            .trim()

        val colonIdx   = line.indexOf(':')
        val searchFrom = if (colonIdx >= 0) colonIdx else 0

        for (m in Regex("""[A-Za-z_]\w*""").findAll(clean)) {
            val typeName = m.value
            if (typeName in allTypes) continue
            // Lowercase builtins are already in allTypes, but double-check
            if (VeldLanguageSpec.isBuiltinType(typeName)) continue
            // Generic containers (List, Map) are in SPECIAL_TYPES → allTypes
            if (VeldLanguageSpec.isSpecialType(typeName)) continue

            val start = lineStart + line.indexOf(typeName, searchFrom)
            val end   = start + typeName.length
            if (start >= lineStart && end <= contentLen && start < end) {
                holder.newAnnotation(HighlightSeverity.ERROR,
                    "Type '$typeName' is not defined. Did you forget to import?")
                    .range(TextRange(start, end)).create()
            }
        }
    }

    // ── Helpers ──────────────────────────────────────────────────────────────

    /** Highlight a word in the raw line at lineStart, searching from searchFrom column. */
    private fun highlightWord(
        word: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder, key: TextAttributesKey,
        searchFrom: Int = 0
    ) {
        val idx   = line.indexOf(word, searchFrom)
        if (idx < 0) return
        val start = lineStart + idx
        val end   = start + word.length
        if (start >= 0 && end <= contentLen && start < end) {
            highlightRange(holder, TextRange(start, end), key)
        }
    }

    private fun highlightRange(holder: AnnotationHolder, range: TextRange, key: TextAttributesKey) {
        holder.newSilentAnnotation(HighlightSeverity.INFORMATION)
            .range(range)
            .textAttributes(key)
            .create()
    }
}

package dev.veld.jetbrains

import com.intellij.lang.annotation.AnnotationHolder
import com.intellij.lang.annotation.Annotator
import com.intellij.lang.annotation.HighlightSeverity
import com.intellij.openapi.editor.DefaultLanguageHighlighterColors
import com.intellij.openapi.editor.colors.TextAttributesKey
import com.intellij.openapi.util.TextRange
import com.intellij.psi.PsiElement
import com.intellij.psi.PsiFile

/**
 * Real-time in-editor annotator for Veld files.
 *
 * Provides:
 *   • Semantic highlighting — distinct colors for every declaration kind, reference kind,
 *     field names, enum values, HTTP methods, path params, @annotations.
 *   • Validation — undefined types, bad imports, invalid HTTP methods, brace mismatches.
 *
 * The annotator operates on the PsiFile level (whole-file pass) so it can correctly
 * resolve cross-line state (brace depth, enum body, model body).
 */
class VeldAnnotator : Annotator {

    companion object {
        // ── Declaration colors ───────────────────────────────────────────────
        val MODEL_DECLARATION = TextAttributesKey.createTextAttributesKey(
            "VELD_MODEL_DECLARATION", DefaultLanguageHighlighterColors.CLASS_NAME
        )
        val ENUM_DECLARATION = TextAttributesKey.createTextAttributesKey(
            "VELD_ENUM_DECLARATION", DefaultLanguageHighlighterColors.INTERFACE_NAME
        )
        val MODULE_DECLARATION = TextAttributesKey.createTextAttributesKey(
            "VELD_MODULE_DECLARATION", DefaultLanguageHighlighterColors.CLASS_NAME
        )
        val ACTION_NAME = TextAttributesKey.createTextAttributesKey(
            "VELD_ACTION_NAME", DefaultLanguageHighlighterColors.FUNCTION_DECLARATION
        )

        // ── Reference colors ─────────────────────────────────────────────────
        val MODEL_REFERENCE = TextAttributesKey.createTextAttributesKey(
            "VELD_MODEL_REFERENCE", DefaultLanguageHighlighterColors.CLASS_REFERENCE
        )
        val ENUM_REFERENCE = TextAttributesKey.createTextAttributesKey(
            "VELD_ENUM_REFERENCE", DefaultLanguageHighlighterColors.INTERFACE_NAME
        )
        val MODULE_REFERENCE = TextAttributesKey.createTextAttributesKey(
            "VELD_MODULE_REFERENCE", DefaultLanguageHighlighterColors.CLASS_REFERENCE
        )

        // ── Member colors ────────────────────────────────────────────────────
        val FIELD_NAME = TextAttributesKey.createTextAttributesKey(
            "VELD_FIELD_NAME", DefaultLanguageHighlighterColors.INSTANCE_FIELD
        )
        val ENUM_VALUE = TextAttributesKey.createTextAttributesKey(
            "VELD_ENUM_VALUE", DefaultLanguageHighlighterColors.CONSTANT
        )

        // ── Annotation color ─────────────────────────────────────────────────
        val ANNOTATION = TextAttributesKey.createTextAttributesKey(
            "VELD_ANNOTATION", DefaultLanguageHighlighterColors.METADATA
        )

        // ── Path parameter color ─────────────────────────────────────────────
        val PATH_PARAM = TextAttributesKey.createTextAttributesKey(
            "VELD_PATH_PARAM", DefaultLanguageHighlighterColors.PARAMETER
        )

        // ── Valid directive keys per block context ───────────────────────────
        /** Keys valid inside action { ... } */
        val ACTION_KEYS = setOf("method", "path", "input", "output", "query", "stream",
            "middleware", "errors", "description")
        /** Keys valid inside module { ... } (top-level, outside actions) */
        val MODULE_KEYS = setOf("description", "prefix")
    }

    // Simple context tracker so we highlight enum values vs. model fields correctly.
    private enum class BlockKind { NONE, MODEL, ENUM, CONSTANTS, MODULE, ACTION }

    override fun annotate(element: PsiElement, holder: AnnotationHolder) {
        if (element !is PsiFile) return
        if (element.virtualFile?.extension != "veld") return

        val project = element.project
        val virtualFile = element.virtualFile ?: return
        val service = VeldProjectService.getInstance(project)
        val content = element.text
        val lines = content.split("\n")

        // Keep the index fresh so visible-type lookups are accurate.
        service.reindexFile(virtualFile, content)

        val visibleModels = service.getVisibleModels(virtualFile).map { it.name }.toSet()
        val visibleEnums  = service.getVisibleEnums(virtualFile).map  { it.name }.toSet()
        val allTypes      = visibleModels + visibleEnums +
                            VeldLanguageSpec.BUILTIN_TYPES + VeldLanguageSpec.SPECIAL_TYPES

        // ── Line-by-line pass ────────────────────────────────────────────────
        var offset     = 0
        var braceDepth = 0
        var bracketDepth = 0  // tracks depth inside [...] lists (e.g. errors: [name:status])
        var blockStack = ArrayDeque<BlockKind>()  // tracks nested block kinds

        for (i in lines.indices) {
            val line        = lines[i]
            val trimmed     = line.trim()
            val lineStart   = offset
            val indentLen   = line.length - line.trimStart().length

            val openBraces   = trimmed.count { it == '{' }
            val closeBraces  = trimmed.count { it == '}' }
            val openBrackets = trimmed.count { it == '[' }
            val closeBrackets = trimmed.count { it == ']' }

            // Current block context (before brace adjustments this line)
            val currentBlock = blockStack.lastOrNull() ?: BlockKind.NONE

            // ── Semantic highlighting ────────────────────────────────────────

            when {
                // ── model declaration ────────────────────────────────────────
                trimmed.startsWith("model ") -> {
                    val m = Regex("""^model\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, MODEL_DECLARATION)
                        // extends parent
                        val ex = Regex("""extends\s+([A-Za-z_]\w*)""").find(trimmed)
                        if (ex != null) {
                            highlightWord(
                                ex.groupValues[1], line, lineStart, content.length, holder, MODEL_REFERENCE,
                                searchFrom = line.indexOf("extends")
                            )
                        }
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.MODEL)
                }

                // ── enum declaration ─────────────────────────────────────────
                trimmed.startsWith("enum ") -> {
                    val m = Regex("""^enum\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, ENUM_DECLARATION)
                    }
                    if (openBraces > closeBraces) {
                        blockStack.addLast(BlockKind.ENUM)
                        // Single-line enum: enum Role { admin user guest }
                        val inlineValues = Regex("""\{([^}]*)\}""").find(trimmed)?.groupValues?.get(1)
                        if (inlineValues != null) {
                            highlightEnumValues(inlineValues, line, lineStart, content.length,
                                line.indexOf('{'), holder)
                            blockStack.removeLast()  // immediately closed
                        }
                    }
                }

                // ── module declaration ────────────────────────────────────────
                trimmed.startsWith("module ") -> {
                    val m = Regex("""^module\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, MODULE_DECLARATION)
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.MODULE)
                }

                // ── constants declaration ─────────────────────────────────────
                trimmed.startsWith("constants ") || trimmed.startsWith("constant ") -> {
                    val m = Regex("""^constants?\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, ENUM_DECLARATION)
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.CONSTANTS)
                }

                // ── action declaration ────────────────────────────────────────
                trimmed.startsWith("action ") -> {
                    val m = Regex("""^action\s+([A-Za-z_]\w*)""").find(trimmed)
                    if (m != null) {
                        highlightWord(m.groupValues[1], line, lineStart, content.length, holder, ACTION_NAME)
                    }
                    if (openBraces > closeBraces) blockStack.addLast(BlockKind.ACTION)
                }

                // ── import / from-import ──────────────────────────────────
                trimmed.startsWith("import") || trimmed.startsWith("from") -> {
                    validateImport(trimmed, line, lineStart, content.length, virtualFile, service, holder)
                }

                // ── top-level prefix: /api/v1 ────────────────────────────────
                trimmed.startsWith("prefix:") && blockStack.isEmpty() -> {
                    // Valid top-level prefix directive — no special handling needed
                }

                // ── inside enum body: enum values ────────────────────────────
                currentBlock == BlockKind.ENUM && trimmed != "{" && trimmed != "}" &&
                        trimmed.isNotEmpty() && !trimmed.startsWith("//") -> {
                    highlightEnumValues(trimmed, line, lineStart, content.length, indentLen, holder)
                }

                // ── inside constants body: NAME: type = value ────────────────
                currentBlock == BlockKind.CONSTANTS && trimmed != "{" && trimmed != "}" &&
                        trimmed.isNotEmpty() && !trimmed.startsWith("//") -> {
                    // Highlight constant field name as FIELD_NAME
                    val constField = Regex("""^([A-Z_][A-Za-z0-9_]*)\s*:""").find(trimmed)
                    if (constField != null) {
                        highlightWord(constField.groupValues[1], line, lineStart, content.length, holder, FIELD_NAME)
                    }
                }

                // ── inside model/action body: directives and fields ───────────
                // Skip directive validation inside [...] lists (e.g. errors: [name:status, ...])
                currentBlock == BlockKind.MODEL || currentBlock == BlockKind.ACTION ||
                currentBlock == BlockKind.MODULE -> {
                    if (bracketDepth == 0) {
                        handleDirectiveOrField(
                            trimmed, line, lineStart, content.length,
                            visibleModels, visibleEnums, allTypes, holder, currentBlock
                        )
                    }
                }

                // ── closing braces ────────────────────────────────────────────
                trimmed == "}" -> { /* handled below */ }
            }

            // ── Brace and bracket depth tracking ────────────────────────────
            braceDepth += openBraces - closeBraces
            bracketDepth = maxOf(0, bracketDepth + openBrackets - closeBrackets)
            repeat(closeBraces) {
                if (blockStack.isNotEmpty()) blockStack.removeLast()
            }

            offset += line.length + 1  // +1 for \n
        }

        // ── Unclosed brace validation ────────────────────────────────────────
        if (braceDepth > 0) {
            val endOffset = content.length
            holder.newAnnotation(
                HighlightSeverity.ERROR,
                "Unclosed brace: $braceDepth opening brace(s) without matching closing brace(s)"
            ).range(TextRange((endOffset - (lines.lastOrNull()?.length ?: 0)).coerceAtLeast(0), endOffset))
                .create()
        } else if (braceDepth < 0) {
            holder.newAnnotation(
                HighlightSeverity.ERROR,
                "Extra closing brace(s): ${-braceDepth} closing brace(s) without matching opening brace(s)"
            ).range(TextRange(0, 1.coerceAtMost(content.length))).create()
        }
    }

    // ── Directive / field handling ───────────────────────────────────────────

    private fun handleDirectiveOrField(
        trimmed: String, line: String, lineStart: Int, contentLen: Int,
        models: Set<String>, enums: Set<String>, allTypes: Set<String>,
        holder: AnnotationHolder, blockKind: BlockKind
    ) {
        if (trimmed.startsWith("//") || trimmed == "{" || trimmed == "}" || trimmed.isEmpty()) return

        // ── Extract the key name if this is a key: value line ────────────────
        val keyMatch = Regex("""^([a-zA-Z_]\w*)\s*:""").find(trimmed)
        if (keyMatch != null && blockKind != BlockKind.MODEL) {
            val key = keyMatch.groupValues[1]
            // Validate directive keys based on block context
            if (blockKind == BlockKind.ACTION && key !in ACTION_KEYS) {
                val start = lineStart + line.indexOf(key)
                val end = start + key.length
                if (start >= lineStart && end <= contentLen && start < end) {
                    holder.newAnnotation(
                        HighlightSeverity.ERROR,
                        "Unknown action directive '$key'. Valid: ${ACTION_KEYS.sorted().joinToString(", ")}"
                    ).range(TextRange(start, end)).create()
                }
                return
            }
            if (blockKind == BlockKind.MODULE && key !in MODULE_KEYS) {
                val start = lineStart + line.indexOf(key)
                val end = start + key.length
                if (start >= lineStart && end <= contentLen && start < end) {
                    holder.newAnnotation(
                        HighlightSeverity.WARNING,
                        "Unexpected key '$key' inside module. Did you mean to put this inside an action?"
                    ).range(TextRange(start, end)).create()
                }
                return
            }
        }

        // ── method directive ──────────────────────────────────────────────────
        if (trimmed.startsWith("method:")) {
            val m = Regex("""method:\s*(\w+)""").find(trimmed)
            if (m != null) {
                val method = m.groupValues[1]
                if (!VeldLanguageSpec.isHttpMethod(method)) {
                    val start = lineStart + line.indexOf(method)
                    val end   = start + method.length
                    if (start >= 0 && end <= contentLen) {
                        holder.newAnnotation(
                            HighlightSeverity.ERROR,
                            "Invalid HTTP method '$method'. Valid: ${VeldLanguageSpec.HTTP_METHODS.joinToString(", ")}"
                        ).range(TextRange(start, end)).create()
                    }
                }
            }
            return
        }

        // ── path directive: highlight :param segments + show resolved path ──
        if (trimmed.startsWith("path:") || trimmed.startsWith("prefix:")) {
            val colonIdx = trimmed.indexOf(':')
            val pathVal  = trimmed.substring(colonIdx + 1).trim()
            highlightPathParams(pathVal, line, lineStart, contentLen, holder)

            // Show the full resolved path as a tooltip
            // We need to find the module prefix and app prefix from context
            val pathStart = lineStart + line.indexOf(pathVal)
            val pathEnd = pathStart + pathVal.length
            if (pathVal.isNotEmpty() && pathStart >= lineStart && pathEnd <= contentLen && pathStart < pathEnd) {
                holder.newAnnotation(HighlightSeverity.INFORMATION,
                    "Resolved: $pathVal (hover an action name to see the full route with all prefixes)")
                    .range(TextRange(pathStart, pathEnd))
                    .tooltip("Route path: <b>$pathVal</b><br/>This path will be combined with the app prefix and module prefix at generation time.")
                    .create()
            }
            return
        }

        // ── input / output / query directives — validate as type references ──
        if (trimmed.startsWith("input:") || trimmed.startsWith("output:") ||
            trimmed.startsWith("query:")
        ) {
            val colonIdx = trimmed.indexOf(':')
            if (colonIdx >= 0) {
                val typeExpr = trimmed.substring(colonIdx + 1).trim()
                highlightTypeReferences(typeExpr, line, lineStart, contentLen, models, enums, holder)
                validateTypeExpression(typeExpr, line, lineStart, contentLen, allTypes, holder)
            }
            return
        }

        // ── middleware directive — just a label name, not a type reference ───
        if (trimmed.startsWith("middleware:")) return

        // ── stream directive — type reference ────────────────────────────────
        if (trimmed.startsWith("stream:")) {
            val colonIdx = trimmed.indexOf(':')
            if (colonIdx >= 0) {
                val typeExpr = trimmed.substring(colonIdx + 1).trim()
                highlightTypeReferences(typeExpr, line, lineStart, contentLen, models, enums, holder)
                validateTypeExpression(typeExpr, line, lineStart, contentLen, allTypes, holder)
            }
            return
        }

        // ── errors directive — list of error names, not type references ──────
        if (trimmed.startsWith("errors:")) return

        // ── description directive: must be a quoted string ────────────────
        if (trimmed.startsWith("description:")) {
            val descColonIdx = trimmed.indexOf(':')
            val descVal = trimmed.substring(descColonIdx + 1).trim()
            if (descVal.isNotEmpty() && !descVal.startsWith("\"")) {
                val start = lineStart + line.indexOf(descVal, descColonIdx)
                val end = start + descVal.length
                if (start >= lineStart && end <= contentLen && start < end) {
                    holder.newAnnotation(
                        HighlightSeverity.ERROR,
                        "Description must be a quoted string, e.g. description: \"User management\""
                    ).range(TextRange(start, end)).create()
                }
            }
            return
        }

        // ── field definition inside a model ──────────────────────────────────
        val fieldMatch = Regex("""^([a-z_]\w*)(\??):\s*(.+?)(?:\s*//.*)?$""").find(trimmed)
        if (fieldMatch != null) {
            val fieldName    = fieldMatch.groupValues[1]
            val rawTypeExpr  = fieldMatch.groupValues[3].trim()

            // Highlight field name
            highlightWord(fieldName, line, lineStart, contentLen, holder, FIELD_NAME)

            // Strip @annotations (e.g. @default(user)) and = value before type processing
            val typeExpr = rawTypeExpr
                .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
                .replace(Regex("""@\w+(?:\([^)]*\))?"""), "")
                .replace(Regex("""@\w+\s+"[^"]*""""), "")
                .trim()

            // Highlight type references
            highlightTypeReferences(typeExpr, line, lineStart, contentLen, models, enums, holder)

            // Validate types
            validateTypeExpression(typeExpr, line, lineStart, contentLen, allTypes, holder)

            // Highlight @annotation(...) clauses on this field line
            highlightAnnotations(rawTypeExpr, line, lineStart, contentLen, holder)

            // Highlight = value default syntax
            highlightDefaultEquals(rawTypeExpr, line, lineStart, contentLen, holder)
        }
    }

    // ── Enum value highlighting ──────────────────────────────────────────────

    private fun highlightEnumValues(
        body: String, fullLine: String, lineStart: Int, contentLen: Int,
        searchFromCol: Int, holder: AnnotationHolder
    ) {
        for (m in Regex("""\b([a-zA-Z_]\w*)\b""").findAll(body)) {
            val start = lineStart + fullLine.indexOf(m.value, searchFromCol)
            val end   = start + m.value.length
            if (start >= lineStart && end <= contentLen && start < end) {
                highlightRange(holder, TextRange(start, end), ENUM_VALUE)
            }
        }
    }

    // ── = value default highlighting and validation ────────────────────────

    private fun highlightDefaultEquals(
        typeExprRaw: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder
    ) {
        val eqMatch = Regex("""=\s*("[^"]*"|-?\d+\.?\d*|true|false|[A-Za-z_]\w*)""").find(typeExprRaw) ?: return
        val colonIdx = line.indexOf(':')
        val searchFrom = if (colonIdx >= 0) colonIdx else 0

        // Highlight the = operator
        val eqIdx = line.indexOf('=', searchFrom)
        if (eqIdx >= 0) {
            val eqStart = lineStart + eqIdx
            val eqEnd = eqStart + 1
            if (eqStart >= lineStart && eqEnd <= contentLen && eqStart < eqEnd) {
                highlightRange(holder, TextRange(eqStart, eqEnd),
                    TextAttributesKey.createTextAttributesKey("VELD_OPERATOR",
                        DefaultLanguageHighlighterColors.OPERATION_SIGN))
            }
        }

        // Highlight the value
        val valStr = eqMatch.groupValues[1]
        val valStart = lineStart + line.indexOf(valStr, if (eqIdx >= 0) eqIdx else searchFrom)
        val valEnd = valStart + valStr.length
        if (valStart >= lineStart && valEnd <= contentLen && valStart < valEnd) {
            val valKey = when {
                valStr.startsWith("\"") -> TextAttributesKey.createTextAttributesKey("VELD_STRING_DEFAULT",
                    DefaultLanguageHighlighterColors.STRING)
                valStr == "true" || valStr == "false" -> TextAttributesKey.createTextAttributesKey("VELD_BOOL_DEFAULT",
                    DefaultLanguageHighlighterColors.KEYWORD)
                valStr.matches(Regex("""-?\d+\.?\d*""")) -> TextAttributesKey.createTextAttributesKey("VELD_NUMBER_DEFAULT",
                    DefaultLanguageHighlighterColors.NUMBER)
                else -> TextAttributesKey.createTextAttributesKey("VELD_IDENT_DEFAULT",
                    DefaultLanguageHighlighterColors.CONSTANT)
            }
            highlightRange(holder, TextRange(valStart, valEnd), valKey)
        }

        // Validate = value against field type (reuse validateDefaultValue)
        val fieldType = typeExprRaw
            .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
            .replace(Regex("""@\w+(?:\([^)]*\))?"""), "")
            .replace(Regex("""@\w+\s+"[^"]*""""), "")
            .replace("[]", "").replace("?", "").trim()
        val defaultVal = valStr
        val error = validateDefaultValue(fieldType, defaultVal)
        if (error != null) {
            if (valStart >= lineStart && valEnd <= contentLen && valStart < valEnd) {
                holder.newAnnotation(HighlightSeverity.ERROR, error.replace("@default for", "Default value for"))
                    .range(TextRange(valStart, valEnd)).create()
            }
        }
    }

    // ── @annotation(...) highlighting and validation ─────────────────────────

    private fun highlightAnnotations(
        typeExprRaw: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder
    ) {
        if (!typeExprRaw.contains('@')) return
        val colonIdx = line.indexOf(':')
        for (m in Regex("""@\w+(?:\([^)]*\))?""").findAll(typeExprRaw)) {
            val searchFrom = if (colonIdx >= 0) colonIdx else 0
            val start = lineStart + line.indexOf(m.value, searchFrom)
            val end   = start + m.value.length
            if (start >= lineStart && end <= contentLen && start < end) {
                highlightRange(holder, TextRange(start, end), ANNOTATION)
                // Validate annotation name
                val annName = m.value.substringAfter('@').substringBefore('(')
                if (annName !in VeldLanguageSpec.KNOWN_ANNOTATIONS) {
                    holder.newAnnotation(
                        HighlightSeverity.WARNING,
                        "Unknown annotation '@$annName'. Known: ${VeldLanguageSpec.KNOWN_ANNOTATIONS.joinToString(", ") { "@$it" }}"
                    ).range(TextRange(start, end)).create()
                }
                // Validate @default value matches field type
                if (annName == "default" && m.value.contains("(")) {
                    val defaultVal = m.value.substringAfter("(").substringBefore(")")
                    // Extract field type from the raw expression (before annotations and = value)
                    val fieldType = typeExprRaw
                        .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
                        .replace(Regex("""@\w+(?:\([^)]*\))?"""), "")
                        .replace("[]", "").replace("?", "").trim()
                    val error = validateDefaultValue(fieldType, defaultVal)
                    if (error != null) {
                        holder.newAnnotation(HighlightSeverity.ERROR, error)
                            .range(TextRange(start, end)).create()
                    }
                }
            }
        }
    }

    /** Validate that a @default value matches the field type. Returns error message or null. */
    private fun validateDefaultValue(fieldType: String, defaultVal: String): String? {
        val isQuoted = defaultVal.startsWith("\"")
        val isBool = defaultVal == "true" || defaultVal == "false"

        return when (fieldType) {
            "string", "date", "datetime", "time", "uuid", "decimal", "bytes" -> {
                if (!isQuoted) "@default for $fieldType must be a quoted string, got $defaultVal"
                else null
            }
            "int", "long" -> when {
                isQuoted -> "@default for $fieldType must be a number, got $defaultVal"
                isBool -> "@default for $fieldType must be a number, got $defaultVal"
                defaultVal.contains(".") -> "@default for $fieldType must be a whole number, got $defaultVal"
                else -> null
            }
            "float" -> when {
                isQuoted -> "@default for float must be a number, got $defaultVal"
                isBool -> "@default for float must be a number, got $defaultVal"
                else -> null
            }
            "bool" -> {
                if (!isBool) "@default for bool must be true or false, got $defaultVal"
                else null
            }
            else -> null // enum or custom type — can't validate without more context
        }
    }

    // ── Path :param highlighting ─────────────────────────────────────────────

    private fun highlightPathParams(
        pathVal: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder
    ) {
        for (m in Regex(""":([\w]+)""").findAll(pathVal)) {
            val searchFrom = line.indexOf(':').let { if (it >= 0) it else 0 }
            val colonStart = lineStart + line.indexOf(":" + m.groupValues[1], searchFrom)
            val end        = colonStart + m.groupValues[1].length + 1
            if (colonStart >= lineStart && end <= contentLen && colonStart < end) {
                highlightRange(holder, TextRange(colonStart, end), PATH_PARAM)
            }
        }
    }

    // ── Type reference highlighting ──────────────────────────────────────────

    private fun highlightTypeReferences(
        typeExpr: String, line: String, lineStart: Int, contentLen: Int,
        models: Set<String>, enums: Set<String>, holder: AnnotationHolder
    ) {
        val colonIdx = line.indexOf(':')
        val searchFrom = if (colonIdx >= 0) colonIdx else 0

        for (m in Regex("""[A-Za-z_]\w*""").findAll(typeExpr)) {
            val typeName = m.value
            val start    = lineStart + line.indexOf(typeName, searchFrom)
            val end      = start + typeName.length
            if (start < lineStart || end > contentLen || start >= end) continue

            val key = when {
                models.contains(typeName) -> MODEL_REFERENCE
                enums.contains(typeName)  -> ENUM_REFERENCE
                VeldLanguageSpec.isSpecialType(typeName) ->
                    TextAttributesKey.createTextAttributesKey("VELD_GENERIC",
                        DefaultLanguageHighlighterColors.CLASS_NAME)
                else -> null
            }
            if (key != null) highlightRange(holder, TextRange(start, end), key)
        }
    }

    // ── Import validation ────────────────────────────────────────────────────

    private fun validateImport(
        trimmed: String, line: String, lineStart: Int, contentLen: Int,
        virtualFile: com.intellij.openapi.vfs.VirtualFile,
        service: VeldProjectService,
        holder: AnnotationHolder
    ) {
        // Accept all valid import formats:
        //   import @models/user    import @models/*    import @models
        //   import /models/user    import /models/*    import /models
        //   import models/user     import models/*     import models
        //   from @models import *  from /models import user  from models import *
        //   import "legacy/path.veld"
        val validPatterns = listOf(
            Regex("""import\s+@\w+(/[\w*]+)?"""),           // import @alias[/name|/*]
            Regex("""import\s+/\w+(/[\w*]+)?"""),           // import /path[/name|/*]
            Regex("""import\s+\w+(/[\w*]+)?"""),            // import alias[/name|/*]
            Regex("""import\s+"[^"]+""""),                   // import "legacy"
            Regex("""from\s+@?\w+\s+import\s+(\*|\w+)"""), // from @?alias import *|name
            Regex("""from\s+/\w+\s+import\s+(\*|\w+)""")   // from /path import *|name
        )
        if (validPatterns.any { it.matches(trimmed) }) {
            // Valid syntax — optionally validate resolved file exists
            val singleFile = Regex("""import\s+(@\w+/\w+)""").find(trimmed)
            if (singleFile != null) {
                val path = singleFile.groupValues[1]
                val resolved = service.resolveImport(path, virtualFile)
                if (resolved == null || !resolved.exists()) {
                    val atIdx = line.indexOf('@')
                    val start = lineStart + atIdx
                    val end   = lineStart + line.trimEnd().length
                    if (atIdx >= 0 && start < end && end <= contentLen) {
                        holder.newAnnotation(HighlightSeverity.WARNING,
                            "Cannot resolve import '$path'. File may not exist yet.")
                            .range(TextRange(start, end)).create()
                    }
                }
            }
        }
    }

    // ── Type validation ──────────────────────────────────────────────────────

    private fun validateTypeExpression(
        typeExpr: String, line: String, lineStart: Int, contentLen: Int,
        allTypes: Set<String>, holder: AnnotationHolder
    ) {
        // Strip @annotations and = value before validation
        val clean = typeExpr
            .replace(Regex("""\s*=\s*(?:"[^"]*"|\S+)"""), "")
            .replace(Regex("""@\w+\([^)]*\)"""), "")
            .trim()

        val colonIdx   = line.indexOf(':')
        val searchFrom = if (colonIdx >= 0) colonIdx else 0

        for (m in Regex("""[A-Za-z_]\w*""").findAll(clean)) {
            val typeName = m.value
            if (typeName in allTypes) continue
            // Lowercase builtins are already in allTypes, but double-check
            if (VeldLanguageSpec.isBuiltinType(typeName)) continue
            // Generic containers (List, Map) are in SPECIAL_TYPES → allTypes
            if (VeldLanguageSpec.isSpecialType(typeName)) continue

            val start = lineStart + line.indexOf(typeName, searchFrom)
            val end   = start + typeName.length
            if (start >= lineStart && end <= contentLen && start < end) {
                holder.newAnnotation(HighlightSeverity.ERROR,
                    "Type '$typeName' is not defined. Did you forget to import?")
                    .range(TextRange(start, end)).create()
            }
        }
    }

    // ── Helpers ──────────────────────────────────────────────────────────────

    /** Highlight a word in the raw line at lineStart, searching from searchFrom column. */
    private fun highlightWord(
        word: String, line: String, lineStart: Int, contentLen: Int,
        holder: AnnotationHolder, key: TextAttributesKey,
        searchFrom: Int = 0
    ) {
        val idx   = line.indexOf(word, searchFrom)
        if (idx < 0) return
        val start = lineStart + idx
        val end   = start + word.length
        if (start >= 0 && end <= contentLen && start < end) {
            highlightRange(holder, TextRange(start, end), key)
        }
    }

    private fun highlightRange(holder: AnnotationHolder, range: TextRange, key: TextAttributesKey) {
        holder.newSilentAnnotation(HighlightSeverity.INFORMATION)
            .range(range)
            .textAttributes(key)
            .create()
    }
}

package dev.veld.jetbrains

import com.intellij.codeInsight.completion.*
import com.intellij.codeInsight.lookup.LookupElementBuilder
import com.intellij.icons.AllIcons
import com.intellij.patterns.PlatformPatterns
import com.intellij.psi.PsiFile
import com.intellij.util.ProcessingContext

/**
 * Context-aware code completion for Veld language.
 * Provides keywords, directives, types, HTTP methods, and models/enums from imports.
 */
class VeldCompletionContributor : CompletionContributor() {

    init {
        extend(
            CompletionType.BASIC,
            PlatformPatterns.psiElement(),
            object : CompletionProvider<CompletionParameters>() {
                override fun addCompletions(
                    parameters: CompletionParameters,
                    context: ProcessingContext,
                    result: CompletionResultSet
                ) {
                    val file = parameters.originalFile
                    val project = file.project
                    val virtualFile = file.virtualFile ?: return
                    val service = VeldProjectService.getInstance(project)

                    val document = parameters.editor.document
                    val offset = parameters.offset
                    val lineNumber = document.getLineNumber(offset)
                    val lineStart = document.getLineStartOffset(lineNumber)
                    val lineText = document.getText(com.intellij.openapi.util.TextRange(lineStart, offset))
                    val fullLineText = document.getText(com.intellij.openapi.util.TextRange(
                        lineStart,
                        document.getLineEndOffset(lineNumber)
                    ))
                    val trimmedBefore = lineText.trimStart()

                    // Determine context
                    val ctx = detectContext(trimmedBefore, fullLineText.trim(), file)

                    when (ctx) {
                        CompletionContext.TOP_LEVEL -> {
                            addKeywords(result)
                            addImportSnippet(result, service, virtualFile)
                        }
                        CompletionContext.AFTER_IMPORT -> {
                            addImportPaths(result, service, virtualFile)
                        }
                        CompletionContext.INSIDE_MODULE -> {
                            addModuleDirectives(result)
                            result.addElement(LookupElementBuilder.create("action")
                                .bold()
                                .withIcon(AllIcons.Nodes.Method)
                                .withInsertHandler { ctx2, _ ->
                                    ctx2.document.insertString(ctx2.tailOffset, " Name {\n    method: \n    path: /\n  }")
                                    ctx2.editor.caretModel.moveToOffset(ctx2.tailOffset - 30)
                                })
                        }
                        CompletionContext.INSIDE_ACTION -> {
                            addActionDirectives(result)
                        }
                        CompletionContext.AFTER_METHOD_COLON -> {
                            addHttpMethods(result)
                        }
                        CompletionContext.AFTER_TYPE_COLON -> {
                            addTypes(result, service, virtualFile)
                        }
                        CompletionContext.AFTER_ANNOTATION_AT -> {
                            addAnnotationCompletions(result)
                        }
                        CompletionContext.AFTER_FIELD_EQUALS -> {
                            // After "fieldName: Type = " — suggest common default values, not types
                            addDefaultValueCompletions(result, trimmedBefore)
                        }
                        CompletionContext.INSIDE_MODEL -> {
                            addBuiltinTypes(result)
                            addCustomTypes(result, service, virtualFile)
                        }
                        CompletionContext.INSIDE_CONSTANTS -> {
                            addBuiltinTypes(result)
                        }
                        CompletionContext.GENERIC -> {
                            addKeywords(result)
                            addTypes(result, service, virtualFile)
                            addActionDirectives(result)
                            addModuleDirectives(result)
                        }
                    }
                }
            }
        )
    }

    private enum class CompletionContext {
        TOP_LEVEL,
        AFTER_IMPORT,
        INSIDE_MODULE,
        INSIDE_ACTION,
        INSIDE_CONSTANTS,
        AFTER_METHOD_COLON,
        AFTER_TYPE_COLON,
        AFTER_ANNOTATION_AT,
        AFTER_FIELD_EQUALS,
        INSIDE_MODEL,
        GENERIC
    }

    private fun detectContext(before: String, fullLine: String, file: PsiFile): CompletionContext {
        // After "import " or "from " -> suggest import paths
        if (before.startsWith("import ") || before == "import" ||
            before.startsWith("from ") || before == "from") {
            return CompletionContext.AFTER_IMPORT
        }

        // After "method: " -> suggest HTTP methods
        if (before.matches(Regex("""method:\s*\w*"""))) {
            return CompletionContext.AFTER_METHOD_COLON
        }

        // After "input: ", "output: ", "query: " -> suggest types
        if (before.matches(Regex("""(input|output|query):\s*\w*"""))) {
            return CompletionContext.AFTER_TYPE_COLON
        }

        // middleware: values are label names, not types — no special context

        // After "fieldname: Type = " -> suggest default values, not types
        if (before.matches(Regex("""[a-z_]\w*\??\s*:\s*\w+.*=\s*\w*$""")) && !before.contains("@")) {
            return CompletionContext.AFTER_FIELD_EQUALS
        }

        // Annotation completion: "fieldname: Type @" or "fieldname?: Type @something"
        // Triggered when the user types "@" after the type in a field definition
        // Must NOT match import lines (those are handled above)
        if (before.matches(Regex("""[a-z_]\w*\??\s*:\s*\w+.*@\w*$""")) && !before.startsWith("import")) {
            return CompletionContext.AFTER_ANNOTATION_AT
        }

        // Standalone "@" typed inside a model block (annotation trigger)
        if (before.endsWith("@") && !before.startsWith("import")) {
            // Delegate to brace-depth check below — if inside model, return annotation context
            val nestCtx = detectNestingContext(file)
            if (nestCtx == CompletionContext.INSIDE_MODEL) {
                return CompletionContext.AFTER_ANNOTATION_AT
            }
        }

        // After "fieldname: " in a model context -> suggest types
        if (before.matches(Regex("""[a-z_]\w*:\s*\w*"""))) {
            return CompletionContext.AFTER_TYPE_COLON
        }

        // Determine nesting by counting braces up to the cursor line
        return detectNestingContext(file)
    }

    private fun detectNestingContext(file: PsiFile): CompletionContext {
        return try {
            val editor = com.intellij.openapi.fileEditor.FileEditorManager.getInstance(file.project)
                .selectedTextEditor
            val caretOffset = editor?.caretModel?.offset ?: file.textLength
            val textUpToCaret = file.text.substring(0, caretOffset.coerceAtMost(file.textLength))
            val lines = textUpToCaret.split("\n")

            var depth = 0
            var inModule = false
            var inAction = false
            var inModel = false
            var inConstants = false

            for (line in lines) {
                val trimmed = line.trim()
                if (trimmed.startsWith("module ") && trimmed.contains("{")) inModule = true
                if (trimmed.startsWith("model ") && trimmed.contains("{")) inModel = true
                if (trimmed.startsWith("constants ") && trimmed.contains("{")) inConstants = true
                if (trimmed.startsWith("constant ") && trimmed.contains("{")) inConstants = true
                if (trimmed.startsWith("action ") && trimmed.contains("{")) inAction = true

                for (ch in trimmed) {
                    if (ch == '{') depth++
                    if (ch == '}') {
                        depth--
                        if (depth <= 0) { inModule = false; inModel = false; inConstants = false; inAction = false; depth = 0 }
                        if (depth <= 1) inAction = false
                    }
                }
            }

            when {
                inAction -> CompletionContext.INSIDE_ACTION
                inModule -> CompletionContext.INSIDE_MODULE
                inModel -> CompletionContext.INSIDE_MODEL
                inConstants -> CompletionContext.INSIDE_CONSTANTS
                else -> CompletionContext.TOP_LEVEL
            }
        } catch (e: Exception) {
            CompletionContext.TOP_LEVEL
        }
    }

    private fun addKeywords(result: CompletionResultSet) {
        for (kw in VeldLanguageSpec.KEYWORDS) {
            result.addElement(
                LookupElementBuilder.create(kw)
                    .bold()
                    .withIcon(AllIcons.Nodes.Tag)
                    .withTypeText("keyword")
            )
        }
    }

    private fun addImportSnippet(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        val root = service.findProjectRoot(file)
        val aliases = if (root != null) service.readAliases(root) else mapOf("models" to "models", "modules" to "modules")

        for ((aliasName, folder) in aliases) {
            // Only suggest aliases that have an existing directory
            val dirExists = root?.findFileByRelativePath(folder)?.isDirectory == true
            if (!dirExists && root != null) continue

            result.addElement(
                LookupElementBuilder.create("import @$aliasName/*")
                    .withIcon(AllIcons.Nodes.Include)
                    .withTypeText("import all from $folder/")
            )
            result.addElement(
                LookupElementBuilder.create("from @$aliasName import *")
                    .withIcon(AllIcons.Nodes.Include)
                    .withTypeText("from...import syntax")
            )
        }

        result.addElement(
            LookupElementBuilder.create("prefix: ")
                .withIcon(AllIcons.Nodes.Property)
                .withTypeText("global route prefix")
                .withInsertHandler { ctx, _ ->
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset)
                }
        )
    }

    private fun addImportPaths(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        val root = service.findProjectRoot(file) ?: return
        // Read aliases from veld.config.json (includes defaults + custom aliases)
        val aliases = service.readAliases(root)
        for ((aliasName, folder) in aliases) {
            val dir = root.findFileByRelativePath(folder) ?: continue
            if (!dir.isDirectory) continue

            // Wildcard import for the whole folder
            result.addElement(
                LookupElementBuilder.create("@$aliasName/*")
                    .withIcon(AllIcons.Nodes.Folder)
                    .withTypeText("import all from $folder/")
                    .withTailText("  (wildcard)", true)
            )
            result.addElement(
                LookupElementBuilder.create("/$aliasName/*")
                    .withIcon(AllIcons.Nodes.Folder)
                    .withTypeText("import all from $folder/")
                    .withTailText("  (path wildcard)", true)
            )

            for (child in dir.children) {
                if (child.extension == "veld") {
                    val name = child.nameWithoutExtension
                    // @alias/name style (recommended)
                    result.addElement(
                        LookupElementBuilder.create("@$aliasName/$name")
                            .withIcon(AllIcons.FileTypes.Any_type)
                            .withTypeText("$folder/$name.veld")
                            .withTailText("  (alias)", true)
                    )
                    // /path/name style
                    result.addElement(
                        LookupElementBuilder.create("/$aliasName/$name")
                            .withIcon(AllIcons.FileTypes.Any_type)
                            .withTypeText("$folder/$name.veld")
                            .withTailText("  (path)", true)
                    )
                }
            }
        }
    }

    private fun addModuleDirectives(result: CompletionResultSet) {
        result.addElement(
            LookupElementBuilder.create("description: \"\"")
                .withPresentableText("description:")
                .withIcon(AllIcons.Nodes.Property)
                .withTypeText("Module description")
                .withInsertHandler { ctx, _ ->
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                }
        )
        result.addElement(
            LookupElementBuilder.create("prefix: /")
                .withPresentableText("prefix:")
                .withIcon(AllIcons.Nodes.Property)
                .withTypeText("Route prefix for all actions")
        )
    }

    private fun addActionDirectives(result: CompletionResultSet) {
        data class Directive(val name: String, val insert: String, val detail: String, val cursorBack: Int)
        val directives = listOf(
            Directive("method", "method: ", "HTTP method (GET, POST, ...)", 0),
            Directive("path", "path: /", "Route path", 0),
            Directive("input", "input: ", "Request body type", 0),
            Directive("output", "output: ", "Response body type", 0),
            Directive("query", "query: ", "Query parameters type", 0),
            Directive("middleware", "middleware: ", "Single middleware", 0),
            Directive("middleware []", "middleware: []", "Middleware list", 1),
            Directive("stream", "stream: ", "Stream output type", 0),
            Directive("errors", "errors: []", "Error codes list", 1),
            Directive("description", "description: \"\"", "Action description", 1),
        )
        for (d in directives) {
            result.addElement(
                LookupElementBuilder.create(d.insert)
                    .withPresentableText("${d.name}:")
                    .withIcon(AllIcons.Nodes.Property)
                    .withTypeText(d.detail)
                    .withInsertHandler(if (d.cursorBack > 0) { ctx, _ ->
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - d.cursorBack)
                    } else null)
            )
        }
    }

    private fun addHttpMethods(result: CompletionResultSet) {
        for (m in VeldLanguageSpec.HTTP_METHODS) {
            result.addElement(
                LookupElementBuilder.create(m)
                    .bold()
                    .withIcon(AllIcons.Actions.Execute)
                    .withTypeText("HTTP method")
            )
        }
    }

    private fun addBuiltinTypes(result: CompletionResultSet) {
        for (t in VeldLanguageSpec.BUILTIN_TYPES) {
            result.addElement(
                LookupElementBuilder.create(t)
                    .withIcon(AllIcons.Nodes.Type)
                    .withTypeText("built-in type")
            )
        }
        for (t in VeldLanguageSpec.SPECIAL_TYPES) {
            result.addElement(
                LookupElementBuilder.create("$t<>")
                    .withPresentableText(t)
                    .withIcon(AllIcons.Nodes.Type)
                    .withTypeText("generic type")
                    .withInsertHandler { ctx, _ ->
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                    }
            )
        }
    }

    private fun addCustomTypes(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        for (model in service.getVisibleModels(file)) {
            val fieldsSummary = model.fields.joinToString(", ") { "${it.name}: ${it.type}" }
            result.addElement(
                LookupElementBuilder.create(model.name)
                    .withIcon(AllIcons.Nodes.Class)
                    .withTypeText("model")
                    .withTailText(" { $fieldsSummary }", true)
            )
        }
        for (enum in service.getVisibleEnums(file)) {
            result.addElement(
                LookupElementBuilder.create(enum.name)
                    .withIcon(AllIcons.Nodes.Enum)
                    .withTypeText("enum")
                    .withTailText(" [${enum.values.joinToString(", ")}]", true)
            )
        }
    }

    private fun addTypes(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        addBuiltinTypes(result)
        addCustomTypes(result, service, file)
    }

    private fun addAnnotationCompletions(result: CompletionResultSet) {
        data class Annotation(val name: String, val snippet: String, val detail: String)
        val annotations = listOf(
            Annotation("@default",    "@default(\$1)",   "Set a default value for this field"),
            Annotation("@example",    "@example(\$1)",   "Provide an example value (shown in docs/OpenAPI)"),
            Annotation("@required",   "@required",       "Mark this field as required (non-nullable)"),
            Annotation("@unique",     "@unique",         "Mark this field as unique in the data store"),
            Annotation("@index",      "@index",          "Add a database index hint for this field"),
            Annotation("@relation",   "@relation(\$1)",  "Define a foreign key relation to another model"),
            Annotation("@deprecated", "@deprecated",     "Mark this field as deprecated"),
            Annotation("@min",        "@min(\$1)",       "Minimum value constraint (int/float)"),
            Annotation("@max",        "@max(\$1)",       "Maximum value constraint (int/float)"),
            Annotation("@minLength",  "@minLength(\$1)", "Minimum string length constraint"),
            Annotation("@maxLength",  "@maxLength(\$1)", "Maximum string length constraint"),
            Annotation("@regex",      "@regex(\$1)",     "Regular expression constraint for strings")
        )
        for (ann in annotations) {
            val item = LookupElementBuilder.create(ann.name)
                .withIcon(AllIcons.Nodes.Annotationtype)
                .withTypeText("annotation")
                .withTailText("  ${ann.detail}", true)
                .withInsertHandler { ctx, _ ->
                    if (ann.snippet.contains("\$1")) {
                        val before = ann.snippet.substringBefore("\$1")
                        val after = ann.snippet.substringAfter("\$1")
                        ctx.document.replaceString(ctx.startOffset, ctx.tailOffset, before + after)
                        ctx.editor.caretModel.moveToOffset(ctx.startOffset + before.length)
                    }
                }
            result.addElement(item)
        }
    }

    private fun addDefaultValueCompletions(result: CompletionResultSet, beforeCursor: String) {
        // Determine the field type from the text before cursor (e.g. "name: bool = ")
        val typeMatch = Regex(""":\s*(\w+)""").find(beforeCursor)
        val fieldType = typeMatch?.groupValues?.get(1) ?: ""

        when (fieldType) {
            "bool" -> {
                result.addElement(LookupElementBuilder.create("true")
                    .bold().withIcon(AllIcons.Nodes.Constant).withTypeText("boolean"))
                result.addElement(LookupElementBuilder.create("false")
                    .bold().withIcon(AllIcons.Nodes.Constant).withTypeText("boolean"))
            }
            "string", "date", "datetime", "uuid", "decimal" -> {
                result.addElement(LookupElementBuilder.create("\"\"")
                    .withPresentableText("\"...\"")
                    .withIcon(AllIcons.Nodes.Constant).withTypeText("string value")
                    .withInsertHandler { ctx, _ ->
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                    })
            }
            "int" -> {
                result.addElement(LookupElementBuilder.create("0")
                    .withIcon(AllIcons.Nodes.Constant).withTypeText("integer"))
            }
            "float" -> {
                result.addElement(LookupElementBuilder.create("0.0")
                    .withIcon(AllIcons.Nodes.Constant).withTypeText("float"))
            }
        }
    }
}

package dev.veld.jetbrains

import com.intellij.codeInsight.completion.*
import com.intellij.codeInsight.lookup.LookupElementBuilder
import com.intellij.icons.AllIcons
import com.intellij.patterns.PlatformPatterns
import com.intellij.psi.PsiFile
import com.intellij.util.ProcessingContext

/**
 * Context-aware code completion for Veld language.
 * Provides keywords, directives, types, HTTP methods, and models/enums from imports.
 */
class VeldCompletionContributor : CompletionContributor() {

    init {
        extend(
            CompletionType.BASIC,
            PlatformPatterns.psiElement(),
            object : CompletionProvider<CompletionParameters>() {
                override fun addCompletions(
                    parameters: CompletionParameters,
                    context: ProcessingContext,
                    result: CompletionResultSet
                ) {
                    val file = parameters.originalFile
                    val project = file.project
                    val virtualFile = file.virtualFile ?: return
                    val service = VeldProjectService.getInstance(project)

                    val document = parameters.editor.document
                    val offset = parameters.offset
                    val lineNumber = document.getLineNumber(offset)
                    val lineStart = document.getLineStartOffset(lineNumber)
                    val lineText = document.getText(com.intellij.openapi.util.TextRange(lineStart, offset))
                    val fullLineText = document.getText(com.intellij.openapi.util.TextRange(
                        lineStart,
                        document.getLineEndOffset(lineNumber)
                    ))
                    val trimmedBefore = lineText.trimStart()

                    // Determine context
                    val ctx = detectContext(trimmedBefore, fullLineText.trim(), file)

                    when (ctx) {
                        CompletionContext.TOP_LEVEL -> {
                            addKeywords(result)
                            addImportSnippet(result, service, virtualFile)
                        }
                        CompletionContext.AFTER_IMPORT -> {
                            addImportPaths(result, service, virtualFile)
                        }
                        CompletionContext.INSIDE_MODULE -> {
                            addModuleDirectives(result)
                            result.addElement(LookupElementBuilder.create("action")
                                .bold()
                                .withIcon(AllIcons.Nodes.Method)
                                .withInsertHandler { ctx2, _ ->
                                    ctx2.document.insertString(ctx2.tailOffset, " Name {\n    method: \n    path: /\n  }")
                                    ctx2.editor.caretModel.moveToOffset(ctx2.tailOffset - 30)
                                })
                        }
                        CompletionContext.INSIDE_ACTION -> {
                            addActionDirectives(result)
                        }
                        CompletionContext.AFTER_METHOD_COLON -> {
                            addHttpMethods(result)
                        }
                        CompletionContext.AFTER_TYPE_COLON -> {
                            addTypes(result, service, virtualFile)
                        }
                        CompletionContext.AFTER_ANNOTATION_AT -> {
                            addAnnotationCompletions(result)
                        }
                        CompletionContext.AFTER_FIELD_EQUALS -> {
                            // After "fieldName: Type = " — suggest common default values, not types
                            addDefaultValueCompletions(result, trimmedBefore)
                        }
                        CompletionContext.INSIDE_MODEL -> {
                            addBuiltinTypes(result)
                            addCustomTypes(result, service, virtualFile)
                        }
                        CompletionContext.INSIDE_CONSTANTS -> {
                            addBuiltinTypes(result)
                        }
                        CompletionContext.GENERIC -> {
                            addKeywords(result)
                            addTypes(result, service, virtualFile)
                            addActionDirectives(result)
                            addModuleDirectives(result)
                        }
                    }
                }
            }
        )
    }

    private enum class CompletionContext {
        TOP_LEVEL,
        AFTER_IMPORT,
        INSIDE_MODULE,
        INSIDE_ACTION,
        INSIDE_CONSTANTS,
        AFTER_METHOD_COLON,
        AFTER_TYPE_COLON,
        AFTER_ANNOTATION_AT,
        AFTER_FIELD_EQUALS,
        INSIDE_MODEL,
        GENERIC
    }

    private fun detectContext(before: String, fullLine: String, file: PsiFile): CompletionContext {
        // After "import " or "from " -> suggest import paths
        if (before.startsWith("import ") || before == "import" ||
            before.startsWith("from ") || before == "from") {
            return CompletionContext.AFTER_IMPORT
        }

        // After "method: " -> suggest HTTP methods
        if (before.matches(Regex("""method:\s*\w*"""))) {
            return CompletionContext.AFTER_METHOD_COLON
        }

        // After "input: ", "output: ", "query: " -> suggest types
        if (before.matches(Regex("""(input|output|query):\s*\w*"""))) {
            return CompletionContext.AFTER_TYPE_COLON
        }

        // middleware: values are label names, not types — no special context

        // After "fieldname: Type = " -> suggest default values, not types
        if (before.matches(Regex("""[a-z_]\w*\??\s*:\s*\w+.*=\s*\w*$""")) && !before.contains("@")) {
            return CompletionContext.AFTER_FIELD_EQUALS
        }

        // Annotation completion: "fieldname: Type @" or "fieldname?: Type @something"
        // Triggered when the user types "@" after the type in a field definition
        // Must NOT match import lines (those are handled above)
        if (before.matches(Regex("""[a-z_]\w*\??\s*:\s*\w+.*@\w*$""")) && !before.startsWith("import")) {
            return CompletionContext.AFTER_ANNOTATION_AT
        }

        // Standalone "@" typed inside a model block (annotation trigger)
        if (before.endsWith("@") && !before.startsWith("import")) {
            // Delegate to brace-depth check below — if inside model, return annotation context
            val nestCtx = detectNestingContext(file)
            if (nestCtx == CompletionContext.INSIDE_MODEL) {
                return CompletionContext.AFTER_ANNOTATION_AT
            }
        }

        // After "fieldname: " in a model context -> suggest types
        if (before.matches(Regex("""[a-z_]\w*:\s*\w*"""))) {
            return CompletionContext.AFTER_TYPE_COLON
        }

        // Determine nesting by counting braces up to the cursor line
        return detectNestingContext(file)
    }

    private fun detectNestingContext(file: PsiFile): CompletionContext {
        return try {
            val editor = com.intellij.openapi.fileEditor.FileEditorManager.getInstance(file.project)
                .selectedTextEditor
            val caretOffset = editor?.caretModel?.offset ?: file.textLength
            val textUpToCaret = file.text.substring(0, caretOffset.coerceAtMost(file.textLength))
            val lines = textUpToCaret.split("\n")

            var depth = 0
            var inModule = false
            var inAction = false
            var inModel = false
            var inConstants = false

            for (line in lines) {
                val trimmed = line.trim()
                if (trimmed.startsWith("module ") && trimmed.contains("{")) inModule = true
                if (trimmed.startsWith("model ") && trimmed.contains("{")) inModel = true
                if (trimmed.startsWith("constants ") && trimmed.contains("{")) inConstants = true
                if (trimmed.startsWith("constant ") && trimmed.contains("{")) inConstants = true
                if (trimmed.startsWith("action ") && trimmed.contains("{")) inAction = true

                for (ch in trimmed) {
                    if (ch == '{') depth++
                    if (ch == '}') {
                        depth--
                        if (depth <= 0) { inModule = false; inModel = false; inConstants = false; inAction = false; depth = 0 }
                        if (depth <= 1) inAction = false
                    }
                }
            }

            when {
                inAction -> CompletionContext.INSIDE_ACTION
                inModule -> CompletionContext.INSIDE_MODULE
                inModel -> CompletionContext.INSIDE_MODEL
                inConstants -> CompletionContext.INSIDE_CONSTANTS
                else -> CompletionContext.TOP_LEVEL
            }
        } catch (e: Exception) {
            CompletionContext.TOP_LEVEL
        }
    }

    private fun addKeywords(result: CompletionResultSet) {
        for (kw in VeldLanguageSpec.KEYWORDS) {
            result.addElement(
                LookupElementBuilder.create(kw)
                    .bold()
                    .withIcon(AllIcons.Nodes.Tag)
                    .withTypeText("keyword")
            )
        }
    }

    private fun addImportSnippet(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        val root = service.findProjectRoot(file)
        val aliases = if (root != null) service.readAliases(root) else mapOf("models" to "models", "modules" to "modules")

        for ((aliasName, folder) in aliases) {
            // Only suggest aliases that have an existing directory
            val dirExists = root?.findFileByRelativePath(folder)?.isDirectory == true
            if (!dirExists && root != null) continue

            result.addElement(
                LookupElementBuilder.create("import @$aliasName/*")
                    .withIcon(AllIcons.Nodes.Include)
                    .withTypeText("import all from $folder/")
            )
            result.addElement(
                LookupElementBuilder.create("from @$aliasName import *")
                    .withIcon(AllIcons.Nodes.Include)
                    .withTypeText("from...import syntax")
            )
        }

        result.addElement(
            LookupElementBuilder.create("prefix: ")
                .withIcon(AllIcons.Nodes.Property)
                .withTypeText("global route prefix")
                .withInsertHandler { ctx, _ ->
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset)
                }
        )
    }

    private fun addImportPaths(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        val root = service.findProjectRoot(file) ?: return
        // Read aliases from veld.config.json (includes defaults + custom aliases)
        val aliases = service.readAliases(root)
        for ((aliasName, folder) in aliases) {
            val dir = root.findFileByRelativePath(folder) ?: continue
            if (!dir.isDirectory) continue

            // Wildcard import for the whole folder
            result.addElement(
                LookupElementBuilder.create("@$aliasName/*")
                    .withIcon(AllIcons.Nodes.Folder)
                    .withTypeText("import all from $folder/")
                    .withTailText("  (wildcard)", true)
            )
            result.addElement(
                LookupElementBuilder.create("/$aliasName/*")
                    .withIcon(AllIcons.Nodes.Folder)
                    .withTypeText("import all from $folder/")
                    .withTailText("  (path wildcard)", true)
            )

            for (child in dir.children) {
                if (child.extension == "veld") {
                    val name = child.nameWithoutExtension
                    // @alias/name style (recommended)
                    result.addElement(
                        LookupElementBuilder.create("@$aliasName/$name")
                            .withIcon(AllIcons.FileTypes.Any_type)
                            .withTypeText("$folder/$name.veld")
                            .withTailText("  (alias)", true)
                    )
                    // /path/name style
                    result.addElement(
                        LookupElementBuilder.create("/$aliasName/$name")
                            .withIcon(AllIcons.FileTypes.Any_type)
                            .withTypeText("$folder/$name.veld")
                            .withTailText("  (path)", true)
                    )
                }
            }
        }
    }

    private fun addModuleDirectives(result: CompletionResultSet) {
        result.addElement(
            LookupElementBuilder.create("description: \"\"")
                .withPresentableText("description:")
                .withIcon(AllIcons.Nodes.Property)
                .withTypeText("Module description")
                .withInsertHandler { ctx, _ ->
                    ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                }
        )
        result.addElement(
            LookupElementBuilder.create("prefix: /")
                .withPresentableText("prefix:")
                .withIcon(AllIcons.Nodes.Property)
                .withTypeText("Route prefix for all actions")
        )
    }

    private fun addActionDirectives(result: CompletionResultSet) {
        data class Directive(val name: String, val insert: String, val detail: String, val cursorBack: Int)
        val directives = listOf(
            Directive("method", "method: ", "HTTP method (GET, POST, ...)", 0),
            Directive("path", "path: /", "Route path", 0),
            Directive("input", "input: ", "Request body type", 0),
            Directive("output", "output: ", "Response body type", 0),
            Directive("query", "query: ", "Query parameters type", 0),
            Directive("middleware", "middleware: ", "Single middleware", 0),
            Directive("middleware []", "middleware: []", "Middleware list", 1),
            Directive("stream", "stream: ", "Stream output type", 0),
            Directive("errors", "errors: []", "Error codes list", 1),
            Directive("description", "description: \"\"", "Action description", 1),
        )
        for (d in directives) {
            result.addElement(
                LookupElementBuilder.create(d.insert)
                    .withPresentableText("${d.name}:")
                    .withIcon(AllIcons.Nodes.Property)
                    .withTypeText(d.detail)
                    .withInsertHandler(if (d.cursorBack > 0) { ctx, _ ->
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - d.cursorBack)
                    } else null)
            )
        }
    }

    private fun addHttpMethods(result: CompletionResultSet) {
        for (m in VeldLanguageSpec.HTTP_METHODS) {
            result.addElement(
                LookupElementBuilder.create(m)
                    .bold()
                    .withIcon(AllIcons.Actions.Execute)
                    .withTypeText("HTTP method")
            )
        }
    }

    private fun addBuiltinTypes(result: CompletionResultSet) {
        for (t in VeldLanguageSpec.BUILTIN_TYPES) {
            result.addElement(
                LookupElementBuilder.create(t)
                    .withIcon(AllIcons.Nodes.Type)
                    .withTypeText("built-in type")
            )
        }
        for (t in VeldLanguageSpec.SPECIAL_TYPES) {
            result.addElement(
                LookupElementBuilder.create("$t<>")
                    .withPresentableText(t)
                    .withIcon(AllIcons.Nodes.Type)
                    .withTypeText("generic type")
                    .withInsertHandler { ctx, _ ->
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                    }
            )
        }
    }

    private fun addCustomTypes(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        for (model in service.getVisibleModels(file)) {
            val fieldsSummary = model.fields.joinToString(", ") { "${it.name}: ${it.type}" }
            result.addElement(
                LookupElementBuilder.create(model.name)
                    .withIcon(AllIcons.Nodes.Class)
                    .withTypeText("model")
                    .withTailText(" { $fieldsSummary }", true)
            )
        }
        for (enum in service.getVisibleEnums(file)) {
            result.addElement(
                LookupElementBuilder.create(enum.name)
                    .withIcon(AllIcons.Nodes.Enum)
                    .withTypeText("enum")
                    .withTailText(" [${enum.values.joinToString(", ")}]", true)
            )
        }
    }

    private fun addTypes(result: CompletionResultSet, service: VeldProjectService, file: com.intellij.openapi.vfs.VirtualFile) {
        addBuiltinTypes(result)
        addCustomTypes(result, service, file)
    }

    private fun addAnnotationCompletions(result: CompletionResultSet) {
        data class Annotation(val name: String, val snippet: String, val detail: String)
        val annotations = listOf(
            Annotation("@default",    "@default(\$1)",   "Set a default value for this field"),
            Annotation("@example",    "@example(\$1)",   "Provide an example value (shown in docs/OpenAPI)"),
            Annotation("@required",   "@required",       "Mark this field as required (non-nullable)"),
            Annotation("@unique",     "@unique",         "Mark this field as unique in the data store"),
            Annotation("@index",      "@index",          "Add a database index hint for this field"),
            Annotation("@relation",   "@relation(\$1)",  "Define a foreign key relation to another model"),
            Annotation("@deprecated", "@deprecated",     "Mark this field as deprecated"),
            Annotation("@min",        "@min(\$1)",       "Minimum value constraint (int/float)"),
            Annotation("@max",        "@max(\$1)",       "Maximum value constraint (int/float)"),
            Annotation("@minLength",  "@minLength(\$1)", "Minimum string length constraint"),
            Annotation("@maxLength",  "@maxLength(\$1)", "Maximum string length constraint"),
            Annotation("@regex",      "@regex(\$1)",     "Regular expression constraint for strings")
        )
        for (ann in annotations) {
            val item = LookupElementBuilder.create(ann.name)
                .withIcon(AllIcons.Nodes.Annotationtype)
                .withTypeText("annotation")
                .withTailText("  ${ann.detail}", true)
                .withInsertHandler { ctx, _ ->
                    if (ann.snippet.contains("\$1")) {
                        val before = ann.snippet.substringBefore("\$1")
                        val after = ann.snippet.substringAfter("\$1")
                        ctx.document.replaceString(ctx.startOffset, ctx.tailOffset, before + after)
                        ctx.editor.caretModel.moveToOffset(ctx.startOffset + before.length)
                    }
                }
            result.addElement(item)
        }
    }

    private fun addDefaultValueCompletions(result: CompletionResultSet, beforeCursor: String) {
        // Determine the field type from the text before cursor (e.g. "name: bool = ")
        val typeMatch = Regex(""":\s*(\w+)""").find(beforeCursor)
        val fieldType = typeMatch?.groupValues?.get(1) ?: ""

        when (fieldType) {
            "bool" -> {
                result.addElement(LookupElementBuilder.create("true")
                    .bold().withIcon(AllIcons.Nodes.Constant).withTypeText("boolean"))
                result.addElement(LookupElementBuilder.create("false")
                    .bold().withIcon(AllIcons.Nodes.Constant).withTypeText("boolean"))
            }
            "string", "date", "datetime", "time", "uuid", "decimal", "bytes" -> {
                result.addElement(LookupElementBuilder.create("\"\"")
                    .withPresentableText("\"...\"")
                    .withIcon(AllIcons.Nodes.Constant).withTypeText("string value")
                    .withInsertHandler { ctx, _ ->
                        ctx.editor.caretModel.moveToOffset(ctx.tailOffset - 1)
                    })
            }
            "int", "long" -> {
                result.addElement(LookupElementBuilder.create("0")
                    .withIcon(AllIcons.Nodes.Constant).withTypeText("integer"))
            }
            "float" -> {
                result.addElement(LookupElementBuilder.create("0.0")
                    .withIcon(AllIcons.Nodes.Constant).withTypeText("float"))
            }
        }
    }
}

