    }

    private fun classifyWord(word: String): IElementType {
        return when (word) {
            "model" -> VeldTokenTypes.MODEL_KEYWORD
            "module" -> VeldTokenTypes.MODULE_KEYWORD
            "action" -> VeldTokenTypes.ACTION_KEYWORD
            "enum" -> VeldTokenTypes.ENUM_KEYWORD
