            "2": { "name": "constant.language.boolean.default-value.veld" }
          }
        },
        {
          "comment": "= number",
          "match": "(=)\\s*(-?\\d+\\.?\\d*)",
          "captures": {
            "1": { "name": "keyword.operator.assignment.veld" },
            "2": { "name": "constant.numeric.default-value.veld" }
          }
        },
        {
          "comment": "= identifier (enum value)",
          "match": "(=)\\s*([A-Za-z_][A-Za-z0-9_]*)",
          "captures": {
            "1": { "name": "keyword.operator.assignment.veld" },
            "2": { "name": "constant.other.default-value.veld" }
          }
        }
      ]
    },

    "annotation": {
      "comment": "@default(value)  or  @required  etc.",
      "patterns": [
        {
          "comment": "@annotation with parenthesized value",
          "match": "(@)([A-Za-z_][A-Za-z0-9_]*)(\\()(?:(\"[^\"]*\")|\\b(true|false)\\b|(-?\\d+\\.?\\d*)|([^)]+))(\\))",
          "captures": {
            "1": { "name": "punctuation.definition.annotation.veld" },
            "2": { "name": "entity.other.attribute-name.annotation.veld" },
            "3": { "name": "punctuation.definition.arguments.veld" },
            "4": { "name": "string.quoted.double.annotation-value.veld" },
            "5": { "name": "constant.language.boolean.annotation-value.veld" },
            "6": { "name": "constant.numeric.annotation-value.veld" },
            "7": { "name": "constant.other.annotation-value.veld" },
            "8": { "name": "punctuation.definition.arguments.veld" }
          }
        },
        {
          "comment": "@annotation without value (e.g. @required, @unique)",
          "match": "(@)([A-Za-z_][A-Za-z0-9_]*)(?!\\()",
          "captures": {
            "1": { "name": "punctuation.definition.annotation.veld" },
            "2": { "name": "entity.other.attribute-name.annotation.veld" }
          }
        }
      ]
    },

    "primitive-type": {
      "comment": "Built-in scalar types",
      "name": "support.type.primitive.veld",
      "match": "\\b(string|int|float|decimal|bool|date|datetime|uuid|bytes|json|any)\\b"
    },

    "generic-type": {
      "comment": "List<T>",
      "match": "\\b(List)(<)([A-Za-z_][A-Za-z0-9_]*)(>)",
      "captures": {
        "1": { "name": "entity.name.type.generic.veld" },
        "2": { "name": "punctuation.definition.generic.begin.veld" },
        "3": { "name": "entity.name.type.class.veld" },
        "4": { "name": "punctuation.definition.generic.end.veld" }
      }
    },

    "map-type": {
      "comment": "Map<K, V>",
      "match": "\\b(Map)(<)([A-Za-z_][A-Za-z0-9_]*)(,\\s*)([A-Za-z_][A-Za-z0-9_]*)(>)",
      "captures": {
        "1": { "name": "entity.name.type.generic.veld" },
        "2": { "name": "punctuation.definition.generic.begin.veld" },
        "3": { "name": "support.type.primitive.veld" },
        "4": { "name": "punctuation.separator.comma.veld" },
        "5": { "name": "entity.name.type.class.veld" },
        "6": { "name": "punctuation.definition.generic.end.veld" }
      }
    },

    "array-marker": {
      "comment": "[] suffix for array types",
      "name": "punctuation.definition.array.veld",
      "match": "\\[\\]"
    },

    "optional-marker": {
      "comment": "? suffix for optional fields",
      "name": "keyword.operator.optional.veld",
      "match": "\\?"
    },

    "type-reference": {
      "comment": "PascalCase type reference (model or enum name)",
      "name": "entity.name.type.class.veld",
      "match": "\\b[A-Z][A-Za-z0-9_]*\\b"
    },

    "http-method-value": {
      "comment": "HTTP method constant values",
      "name": "constant.language.http-method.veld",
      "match": "\\b(GET|POST|PUT|DELETE|PATCH|HEAD|OPTIONS)\\b"
    },

    "path-content": {
      "comment": "Path value with :param highlighting",
      "patterns": [
        {
          "comment": ":paramName path segment",
          "match": "(:)([A-Za-z_][A-Za-z0-9_]*)",
          "captures": {
            "1": { "name": "keyword.operator.path-param.veld" },
            "2": { "name": "variable.other.path-parameter.veld" }
          }
        },
        {
          "name": "string.other.path.veld",
          "match": "[^:\\s]+"
        },
        {
          "name": "punctuation.separator.path.veld",
          "match": "/"
        }
      ]
    },

    "field-type-content": {
      "comment": "Type expression for field values: primitives, generics, maps, annotations",
      "patterns": [
        { "include": "#annotation" },
        { "include": "#generic-type" },
        { "include": "#map-type" },
        { "include": "#primitive-type" },
        { "include": "#array-marker" },
        { "include": "#type-reference" },
        { "include": "#string" }
      ]
    },

    "type-expr-content": {
      "comment": "Type expression for directive values (no annotations)",
      "patterns": [
        { "include": "#generic-type" },
        { "include": "#map-type" },
        { "include": "#primitive-type" },
        { "include": "#array-marker" },
        { "include": "#type-reference" }
      ]
    },

    "model-block": {
      "comment": "model Name { ... }  or  model Name extends Parent { ... }",
      "begin": "^\\s*(model)\\s+([A-Za-z_][A-Za-z0-9_]*)(?:\\s+(extends)\\s+([A-Za-z_][A-Za-z0-9_]*))?\\s*(\\{)",
      "end": "^\\s*\\}",
      "beginCaptures": {
        "1": { "name": "storage.type.model.veld" },
        "2": { "name": "entity.name.type.model.veld" },
        "3": { "name": "storage.modifier.extends.veld" },
        "4": { "name": "entity.name.type.inherited.veld" },
        "5": { "name": "punctuation.definition.block.begin.veld" }
      },
      "endCaptures": {
        "0": { "name": "punctuation.definition.block.end.veld" }
      },
      "patterns": [
        { "include": "#comment" },
        { "include": "#field-definition" }
      ]
    },

    "field-definition": {
      "comment": "fieldName: Type  or  fieldName?: Type  or  fieldName: Type = value  or  fieldName: Type @default(val)",
      "match": "^\\s*([a-z_][A-Za-z0-9_]*)(\\??)\\s*(:)\\s*(.+?)\\s*(?://.*)?$",
      "captures": {
        "1": { "name": "variable.other.field.veld" },
        "2": { "name": "keyword.operator.optional.veld" },
        "3": { "name": "punctuation.separator.key-value.veld" },
        "4": {
          "patterns": [
            { "include": "#default-value" },
            { "include": "#annotation" },
            { "include": "#generic-type" },
            { "include": "#map-type" },
            { "include": "#primitive-type" },
            { "include": "#array-marker" },
            { "include": "#type-reference" },
            { "include": "#string" }
          ]
        }
      }
    },

    "enum-block": {
      "comment": "enum Role { admin user guest }",
      "begin": "^\\s*(enum)\\s+([A-Za-z_][A-Za-z0-9_]*)\\s*(\\{)",
      "end": "^\\s*\\}",
      "beginCaptures": {
        "1": { "name": "storage.type.enum.veld" },
        "2": { "name": "entity.name.type.enum.veld" },
        "3": { "name": "punctuation.definition.block.begin.veld" }
      },
      "endCaptures": {
        "0": { "name": "punctuation.definition.block.end.veld" }
      },
      "patterns": [
        { "include": "#comment" },
        {
          "comment": "Enum values — one or more identifiers on a line",
          "match": "\\b([a-zA-Z_][A-Za-z0-9_]*)\\b",
          "captures": {
            "1": { "name": "constant.other.enum-value.veld" }
          }
        }
      ]
    },

    "constants-block": {
      "comment": "constants GroupName { NAME: type = value ... } or constant GroupName { ... }",
      "begin": "^\\s*(constants?)\\s+([A-Za-z_][A-Za-z0-9_]*)\\s*(\\{)",
      "end": "^\\s*\\}",
      "beginCaptures": {
        "1": { "name": "storage.type.constants.veld" },
        "2": { "name": "entity.name.type.constants.veld" },
        "3": { "name": "punctuation.definition.block.begin.veld" }
      },
      "endCaptures": {
        "0": { "name": "punctuation.definition.block.end.veld" }
      },
      "patterns": [
        { "include": "#comment" },
        { "include": "#description-directive" },
        { "include": "#constant-field-definition" }
      ]
    },

    "constant-field-definition": {
      "comment": "CONSTANT_NAME: type = value",
      "match": "^\\s*([A-Z_][A-Za-z0-9_]*)\\s*(:)\\s*(string|int|float|decimal|bool|date|datetime|uuid)\\s*(=)\\s*(\"[^\"]*\"|\\-?\\d+\\.?\\d*|true|false)",
      "captures": {
        "1": { "name": "variable.other.constant.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" },
        "3": { "name": "support.type.primitive.veld" },
        "4": { "name": "keyword.operator.assignment.veld" },
        "5": {
          "patterns": [
            { "include": "#string" },
            { "include": "#number" },
            { "include": "#boolean" }
          ]
        }
      }
    },

    "module-block": {
      "comment": "module Name { ... }",
      "begin": "^\\s*(module)\\s+([A-Za-z_][A-Za-z0-9_]*)\\s*(\\{)",
      "end": "^\\s*\\}",
      "beginCaptures": {
        "1": { "name": "storage.type.module.veld" },
        "2": { "name": "entity.name.namespace.module.veld" },
        "3": { "name": "punctuation.definition.block.begin.veld" }
      },
      "endCaptures": {
        "0": { "name": "punctuation.definition.block.end.veld" }
      },
      "patterns": [
        { "include": "#comment" },
        { "include": "#action-block" },
        { "include": "#description-directive" },
        { "include": "#prefix-directive" }
      ]
    },

    "action-block": {
      "comment": "action GetUser { ... }",
      "begin": "^\\s*(action)\\s+([A-Za-z_][A-Za-z0-9_]*)\\s*(\\{)",
      "end": "^\\s*\\}",
      "beginCaptures": {
        "1": { "name": "keyword.other.action.veld" },
        "2": { "name": "entity.name.function.action.veld" },
        "3": { "name": "punctuation.definition.block.begin.veld" }
      },
      "endCaptures": {
        "0": { "name": "punctuation.definition.block.end.veld" }
      },
      "patterns": [
        { "include": "#comment" },
        { "include": "#method-directive" },
        { "include": "#path-directive" },
        { "include": "#errors-directive" },
        { "include": "#type-directive" },
        { "include": "#description-directive" }
      ]
    },

    "description-directive": {
      "comment": "description: \"...\"",
      "begin": "^\\s*(description)\\s*(:)\\s*",
      "end": "$",
      "beginCaptures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" }
      },
      "patterns": [
        { "include": "#string" }
      ]
    },

    "prefix-directive": {
      "comment": "prefix: /api/v1",
      "begin": "^\\s*(prefix)\\s*(:)\\s*",
      "end": "$",
      "beginCaptures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" }
      },
      "patterns": [
        { "include": "#path-content" }
      ]
    },

    "method-directive": {
      "comment": "method: GET",
      "match": "^\\s*(method)\\s*(:)\\s*(GET|POST|PUT|DELETE|PATCH|HEAD|OPTIONS)\\b",
      "captures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" },
        "3": { "name": "constant.language.http-method.veld" }
      }
    },

    "path-directive": {
      "comment": "path: /users/:id",
      "begin": "^\\s*(path)\\s*(:)\\s*",
      "end": "$",
      "beginCaptures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" }
      },
      "patterns": [
        { "include": "#path-content" }
      ]
    },

    "type-directive": {
      "comment": "input: User  /  output: List<User>  /  query: Filter  /  middleware: AuthGuard  /  stream: Message",
      "begin": "^\\s*(input|output|query|middleware|stream)\\s*(:)\\s*",
      "end": "$",
      "beginCaptures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" }
      },
      "patterns": [
        { "include": "#type-expr-content" }
      ]
    },

    "errors-directive": {
      "comment": "errors: [NotFound, Unauthorized, Conflict]",
      "begin": "^\\s*(errors)\\s*(:)\\s*(\\[)",
      "end": "(\\])",
      "beginCaptures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" },
        "3": { "name": "punctuation.definition.array.begin.veld" }
      },
      "endCaptures": {
        "1": { "name": "punctuation.definition.array.end.veld" }
      },
      "patterns": [
        {
          "name": "variable.other.error-code.veld",
          "match": "\\b[A-Za-z_][A-Za-z0-9_]*\\b"
        },
        {
          "name": "punctuation.separator.comma.veld",
          "match": ","
        }
      ]
    },

    "block": {
      "name": "meta.block.veld",
      "begin": "\\{",
      "end": "\\}",
      "beginCaptures": { "0": { "name": "punctuation.definition.block.begin.veld" } },
      "endCaptures":   { "0": { "name": "punctuation.definition.block.end.veld" } }
    }
  }
}

{
  "$schema": "https://raw.githubusercontent.com/martinring/tmlanguage/master/tmlanguage.json",
  "name": "Veld",
  "scopeName": "source.veld",
  "fileTypes": ["veld"],
  "patterns": [
    { "include": "#comment" },
    { "include": "#top-level-prefix" },
    { "include": "#from-import-statement" },
    { "include": "#import-statement" },
    { "include": "#model-block" },
    { "include": "#enum-block" },
    { "include": "#constants-block" },
    { "include": "#module-block" }
  ],
  "repository": {

    "comment": {
      "patterns": [
        {
          "name": "comment.block.veld",
          "begin": "/\\*",
          "end": "\\*/"
        },
        {
          "name": "comment.line.double-slash.veld",
          "match": "//.*$"
        }
      ]
    },

    "string": {
      "name": "string.quoted.double.veld",
      "begin": "\"",
      "end": "\"",
      "patterns": [
        { "name": "constant.character.escape.veld", "match": "\\\\." }
      ]
    },

    "number": {
      "name": "constant.numeric.veld",
      "match": "\\b\\d+(\\.\\d+)?\\b"
    },

    "boolean": {
      "name": "constant.language.boolean.veld",
      "match": "\\b(true|false)\\b"
    },

    "import-statement": {
      "comment": "All import variants: import @models/auth, import /models/*, import models, etc.",
      "match": "^\\s*(import)\\s+((?:@?\\w+)?(?:/[\\w*]+)*|\"[^\"]+\")",
      "captures": {
        "1": { "name": "keyword.control.import.veld" },
        "2": { "name": "entity.name.import.veld" }
      }
    },

    "from-import-statement": {
      "comment": "from @models import * / from /models import user / from models import *",
      "match": "^\\s*(from)\\s+((?:@?\\w+)?(?:/[\\w]+)*)\\s+(import)\\s+(\\*|\\w+)",
      "captures": {
        "1": { "name": "keyword.control.import.veld" },
        "2": { "name": "entity.name.namespace.veld" },
        "3": { "name": "keyword.control.import.veld" },
        "4": { "name": "entity.name.import.veld" }
      }
    },

    "top-level-prefix": {
      "comment": "prefix: /api/v1 at top level",
      "begin": "^(prefix)\\s*(:)\\s*",
      "end": "$",
      "beginCaptures": {
        "1": { "name": "support.function.directive.veld" },
        "2": { "name": "punctuation.separator.key-value.veld" }
      },
      "patterns": [
        { "include": "#path-content" }
      ]
    },

    "default-value": {
      "comment": "= value  default value syntax (e.g. page: int = 0)",
      "patterns": [
        {
          "comment": "= \"string\"",
          "match": "(=)\\s*(\"[^\"]*\")",
          "captures": {
            "1": { "name": "keyword.operator.assignment.veld" },
            "2": { "name": "string.quoted.double.default-value.veld" }
          }
        },
        {
          "comment": "= true/false",
          "match": "(=)\\s*\\b(true|false)\\b",
          "captures": {
            "1": { "name": "keyword.operator.assignment.veld" },
            "2": { "name": "constant.language.boolean.default-value.veld" }
          }
        },
        {
          "comment": "= number",
          "match": "(=)\\s*(-?\\d+\\.?\\d*)",
          "captures": {
            "1": { "name": "keyword.operator.assignment.veld" },
            "2": { "name": "constant.numeric.default-value.veld" }
          }
        },
        {
          "comment": "= identifier (enum value)",
          "match": "(=)\\s*([A-Za-z_][A-Za-z0-9_]*)",
          "captures": {
            "1": { "name": "keyword.operator.assignment.veld" },
            "2": { "name": "constant.other.default-value.veld" }
          }
        }
      ]
    },

    "annotation": {
      "comment": "@default(value)  or  @required  etc.",
      "patterns": [
        {
          "comment": "@annotation with parenthesized value",
          "match": "(@)([A-Za-z_][A-Za-z0-9_]*)(\\()(?:(\"[^\"]*\")|\\b(true|false)\\b|(-?\\d+\\.?\\d*)|([^)]+))(\\))",
          "captures": {
            "1": { "name": "punctuation.definition.annotation.veld" },
            "2": { "name": "entity.other.attribute-name.annotation.veld" },
            "3": { "name": "punctuation.definition.arguments.veld" },
            "4": { "name": "string.quoted.double.annotation-value.veld" },
            "5": { "name": "constant.language.boolean.annotation-value.veld" },
            "6": { "name": "constant.numeric.annotation-value.veld" },
            "7": { "name": "constant.other.annotation-value.veld" },
            "8": { "name": "punctuation.definition.arguments.veld" }
          }
        },
        {
          "comment": "@annotation without value (e.g. @required, @unique)",
          "match": "(@)([A-Za-z_][A-Za-z0-9_]*)(?!\\()",
          "captures": {
            "1": { "name": "punctuation.definition.annotation.veld" },
            "2": { "name": "entity.other.attribute-name.annotation.veld" }
          }
        }
      ]
    },

    "primitive-type": {
      "comment": "Built-in scalar types",
      "name": "support.type.primitive.veld",
      "match": "\\b(string|int|long|float|decimal|bool|date|datetime|time|uuid|bytes|json|any)\\b"
    },

    "generic-type": {
